INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('26', 'arcvaults', 'The Programmable Escrow Payments', 'ArcVault is a programmable USDC escrow gateway built on the Arc Blockchain. It lets two parties lock stablecoin funds in a smart contract and release them only when agreed conditions are met, no trust required.\n\nWHAT IT DOES:\n\nCreates escrows — a buyer deposits USDC into a contract, locked until the seller delivers\n\nMilestone-based releases — funds can be split into milestones and released incrementally\n\nDispute resolution — if there''s a disagreement, an arbitrator can step in to decide\n\nAuto-release — funds automatically release after a deadline if no dispute is raised\nWHO IS IT FOR:\n\nFreelancers & clients — secure payments for gigs, contracts, and project work\n\nCrypto-native teams — trustless payments between parties who don''t know each other\n\nDAOs & communities — programmatic fund distribution with accountability\n\nAnyone trading services on-chain — escrow removes counterparty risk using USDC (no volatile tokens)', 'Payments', 'https://i.ibb.co/Z68XnBC5/arcvault-logo-png.png', 'https://arcvaults.vercel.app/', 'https://x.com/Arablooded', 'https://github.com/OxygenWeb3/arcvaults.git', 'oxygen_web3', NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-01T19:15:42.090Z"', NULL, 'Ibrahimabdulganniy@gmail.com', 'claimed', NULL, 20, 'arcvaults', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
