INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('77', 'ArcForge', 'AI-powered code generator for Circle''s stablecoin-native stack.', 'Arc Forge is an interactive developer tool that combines:\n\nCircle Skills — 8 curated SKILL.md files encoding Circle''s best-practice patterns for USDC payments, crosschain transfers, wallets, and smart contracts\nClaude API — claude-sonnet-4 generates context-aware, skill-grounded code\nCircle MCP server — live SDK signatures, contract addresses, and chain IDs pulled directly from Circle''s infrastructure\nYou describe what you want to build. Arc Forge picks the right skill context, composes a grounded prompt, and returns clean, annotated code you can drop into your project.', 'DeFi', 'https://i.ibb.co/NdQzgVMB/5897521157689249020-jpg.jpg', 'https://www.arcforgeapp.com/', NULL, 'https://github.com/Isaaco3349/arc-forge', NULL, NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-11T16:30:07.790Z"', NULL, 'isaaconyeomah@gmail.com', 'claimed', NULL, 18, 'arcforge', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('44', 'Arctimes', 'ARC Times is a media and information platform built for the ARC Network ecosystem.', 'The platform provides news, statistics, and multimedia content to help the community stay informed about the development and growth of the ARC ecosystem.\n\nInstead of scattered updates across different platforms, ARC Times brings everything together in one place — making ecosystem discovery easier, clearer, and more accessible.\n\nThe goal of the project is to create a central hub for ARC ecosystem updates, statistics, and community activity.', 'Social', 'https://i.ibb.co/hRm6d2zd/Gemini-Generated-Image-if8uobif8uobif8u-png.png', 'https://arctimes.net/', 'wentyom', 'https://github.com/wentyom/arctimesnet', NULL, NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-06T21:14:39.304Z"', NULL, 'info@ruvion.tech', 'claimed', NULL, 28, 'arctimes', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
