INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('70', 'arcvaults', 'Programmable Escrow Payments', 'ArcVault is a programmable USDC escrow gateway built on the Arc Blockchain. It lets two parties lock stablecoin funds in a smart contract and release them only when agreed conditions are met — no trust required.\n\nWhat it does:\n\nCreates escrows — a buyer deposits USDC into a contract, locked until the seller delivers\nMilestone-based releases — funds can be split into milestones and released incrementally\nDispute resolution — if there''s a disagreement, an arbitrator can step in to decide\nAuto-release — funds automatically release after a deadline if no dispute is raised\n\nWho it''s for:\n\nFreelancers & clients — secure payments for gigs, contracts, and project work\nCrypto-native teams — trustless payments between parties who don''t know each other\nDAOs & communities — programmatic fund distribution with accountability\nAnyone trading services on-chain — escrow removes counterparty risk using USDC (no volatile tokens)', 'Payments', 'https://i.ibb.co/JRR06NJq/arcvault-logo-png.png', 'https://arcvaults.vercel.app/', '@Arablooded', 'https://github.com/OxygenWeb3/arcvaults.git', '@oxygen_web3', '0x963deb962040cc9784fadf276b0165fac0cd8091', FALSE, TRUE, TRUE, NULL, '"2026-04-10T17:49:27.218Z"', NULL, 'Ibrahimabdulganniy@gmail.com', 'claimed', NULL, 15, 'arcvaults-mnt7afqp', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
