INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('40', 'TrusttCircle', 'Pool money with people you know. Contribute weekly. Receive a full lump sum when it is your turn. The smart contract handles everything else.', 'TrustCircle is an onchain savings circle application where groups of trusted users pool USDC weekly and rotate payouts. Every circle is governed entirely by code. Contributions are enforced, payouts are automatic, and reputation is tracked permanently onchain. There is no human middleman, no "I will pay tomorrow," and no trust required outside of the contract itself.', 'Infrastructure', 'https://i.ibb.co/C5VZYPYf/image-2026-04-06-12-56-27-png.png', 'https://trusttcircle.online', NULL, 'https://github.com/mystiquemide/trustcircle', NULL, '0x9549002af3b4b806d1f3d16287189143f44a7e18', FALSE, TRUE, TRUE, NULL, '"2026-04-06T12:02:05.609Z"', NULL, 'mide27145@gmail.com', 'claimed', NULL, 88, 'trusttcircle', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('68', 'ArcFlow', 'The payment layer on Arc — streaming, invoicing, and paywall powered by native USDC.', 'ArcFlow is an onchain payments platform built on Arc Testnet with native USDC. It combines three core primitives in one product: real-time payment streams, one-time invoice settlement, and a pay-per-request marketplace for APIs. Users can stream funds continuously, settle fixed invoices instantly, or monetize services with usage-based payments, with service ownership, pricing, and provider earnings.', 'Payments', 'https://i.ibb.co/4wFZWDFk/Ads-z-tasar-m-2026-04-10-T142857-843-png.png', 'https://www.flowonarc.net/', NULL, 'https://github.com/dlkakbs/arcflow', NULL, '0xab78614fed57bb451b70ee194fc4043cadcc39ef, 0x8d533a6df78ef01f6e4e998588d3ccb21f668486, 0xc805da7670ae48cd14bf50434f919c2efe3ed6bd', FALSE, TRUE, TRUE, NULL, '"2026-04-10T12:03:51.076Z"', NULL, 'flowonarc@gmail.com', 'claimed', NULL, 44, 'arcflow', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('90', 'Mint on Arc', 'Arc''s Leading NFT Launchpad', 'Mint on Arc is an NFT launchpad and minting platform on ARC . It lets creators set up and launch NFT drops (supply, pricing, launch schedule, whitelist stages, payout splits, and royalty settings), and lets collectors discover live/upcoming collections and mint directly from dedicated mint pages. It also includes a MOA marketplace for Mint on Arc official collection.', 'NFT', 'https://i.ibb.co/GvZR0cq1/mintonarclogo-png.png', 'soon', 'Mintonarc', NULL, NULL, 'soon', FALSE, TRUE, TRUE, NULL, '"2026-04-15T10:44:34.073Z"', NULL, 'mintonarcofficial@gmail.com', 'claimed', NULL, 45, 'mint-on-arc', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('88', 'AUTONOMAMOBILE', 'The world’s first Intent-Driven Phone. Sensory nerves for Global AI Agents. The digital passport & medium of exchange for the Multi-Agent & IoT era.', 'AUTONOMA will transform mobile phones from mere "communication tools" into "digital life carriers." No longer just tools, they will become economic entities with independent intent, autonomously seeking computing power, purchasing data, and mutually utilizing it. Each AUTONOMA is a mobile economic node. It uses the most robust equipment to run the most stable native L1 stablecoin.\n\nEvery heartbeat you make contributes to the real-world settlement of Web3.\n\n"The First AI Terminal for Global Money."', 'Infrastructure', 'https://i.ibb.co/Cs40mStf/0-ULZXMl-400x400-jpg.jpg', 'https://autonomamobile.com/', '@autonomamobile', NULL, NULL, NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-15T00:36:32.160Z"', NULL, 'autonomamobile@tutamail.com', 'claimed', NULL, 13, 'autonomamobile', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('102', 'Flowfi-Agent', 'FlowFi Agent is an AI-powered assistant built on Arc that automates and manages your on-chain financial activities from one dashboard.', 'FlowFi Agent is basically an AI-powered finance/DeFi assistant built on Arc that helps you manage and interact with on-chain capital (like USDC) from a single dashboard.\nIt automates actions like tracking funds, deploying liquidity, swapping, bridging, transfering funds and executing financial strategies, acting like a “smart agent” that handles money flow and decisions for you.', 'AI', 'https://i.ibb.co/1GmLLHqx/8e23ad16-7f2d-45d5-a721-3f615c68ead8-png.png', 'https://flowfiagent.vercel.app/', NULL, 'https://github.com/web3-attorney/flowfi-agent-v3', NULL, NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-20T09:55:40.614Z"', NULL, 'debare0707@gmail.com', 'claimed', NULL, 9, 'flowfi-agent', 'e90cc9639834dcc5f1db8a4a94ab37ee775b56175bdf4aa2027d56a02913e5c2', '"2026-04-20T14:47:24.973Z"', '"2026-04-20T14:17:43.636Z"', 'debare0707@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('94', 'Custodex', 'A Conditional Escrow Payments Infra Built On Arc', 'Custodex (Conditional Payments) is a decentralized, non-custodial escrow protocol built to eliminate counterparty risk in digital transactions. Deployed on the Arc Testnet, the platform allows users to securely lock USDC into smart contracts that only release funds when specific, pre-agreed conditions are met.\n\nThe protocol supports three distinct escrow models to cover a wide range of transactional needs:\n\nTimelocked Escrows: Features strictly enforced cooling-off periods and claim deadlines, ensuring funds are automatically reclaimable if the receiving party fails to act.\n\nMediated Escrows: Introduces a neutral third-party Arbiter to oversee the transaction. Includes an integrated on-chain Resolution Room where parties can upload evidence and chat, allowing the Arbiter to confidently disburse or refund the locked assets.\n\nBonded Escrows: Requires the receiver to stake a financial bond upfront. If a dispute is raised and ruled against the receiver, both the payment and the staked bond are permanently slashed and burned.\n\nBuilt with Next.js, TypeScript, Tailwind CSS, and Supabase, Custodex provides a seamless, highly responsive interface that abstracts away the complexities of Web3 while maintaining trustless, instant settlement.', 'Payments', 'https://i.ibb.co/Cs5658jn/1003234741-png.png', 'https://custodex-dev.vercel.app/', NULL, 'https://github.com/Atubulated/conditional-payments', NULL, '0x199a2b36e9f2b8a561c167190ded5c82ed32079c', FALSE, TRUE, TRUE, NULL, '"2026-04-15T15:35:41.001Z"', NULL, 'atubudaniel.da@gmail.com', 'claimed', NULL, 12, 'custodex', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('31', 'Synthra', 'All-in-one DeFi hub for emerging chains', 'Synthra is an all-in-one DeFi hub designed to become the core trading and liquidity infrastructure across emerging EVM chains. It provides a seamless environment for swapping, liquidity provisioning, and advanced trading tools, all within a single platform. By focusing on performance, usability, and early deployment on growing ecosystems, Synthra aims to establish itself as the go-to decentralized trading platform wherever new blockchain economies emerge.', 'DeFi', 'https://i.ibb.co/C5pXmFVJ/synthra-logo-3-png.png', 'https://synthra.org', '@synthra_finance', 'https://github.com/synthra_swap', 'discord.gg/bRRbd25FKJ', NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-03T09:22:31.710Z"', NULL, 'jacko06v@synthra.org', 'verified', NULL, 94, 'synthra', '12958cfc59cca87e47d8e60966ac36189b3c03ba3b0c4c5b7c5fee49c44b80d3', '"2026-04-15T14:54:58.780Z"', '"2026-04-15T14:25:13.659Z"', 'jacko06v@synthra.org', '0x6063e834928eac1ca47ac5da27838079a103e305', 'rome', 'italy', 41.8933203, 12.4829321) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('73', 'Arc Wallet Assistant', 'Talk to your Arc wallet in plain english', 'Arc Wallet Assistant lets you interact with your Arc wallet using natural language. Instead of navigating block explorers or copying addresses, you just ask. Check your USDC balance, understand a transaction, get help with crosschain transfers via CCTP all in plain english. It connects to Circle''s Web3 APIs to pull live wallet data and uses AI to give you real answers, not links to documentation. Built fully on Arc with USDC as gas.', 'AI', 'https://i.ibb.co/pvFKQNRt/arc-wallet-logo-png.png', 'https://arc-wallet-assistant.vercel.app/', '@_Haboye', 'https://github.com/selcouthweb3/arc-wallet-assistant', NULL, '0x6fa971157cf2cd64bd9765e0ee14a4c89ba5defd', FALSE, TRUE, TRUE, NULL, '"2026-04-11T14:10:00.348Z"', NULL, 'semilore05007@gmail.com', 'claimed', NULL, 76, 'arc-wallet-assistant', '8983b8227c5c9087b655cd08a5f139191f238867e3b750f57d0ddddb3ca503ee', '"2026-04-11T15:33:56.717Z"', '"2026-04-11T15:04:16.227Z"', 'semilore05007@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('84', 'Arcdict Markets', 'stables decentralized prediction market on arc. Still in building and we would love you to stick around for testing and genuine feedback🫶. updates would be communicated through the builders X', 'Users: Traders, degens, analysts, and curious observers who want to bet on real-world outcomes (sports, crypto prices, politics, protocol governance)\nProblem it solves:\n\nCentralized prediction markets (Polymarket clones on CEXs) require trust in an operator who can manipulate outcomes or freeze funds\nTraditional bookmakers take huge margins and restrict access by geography\nExisting on-chain markets (Polymarket) have high gas costs on Ethereum that make small bets uneconomical\n\nArc fixes the small bet problem, USDC gas means a $2 bet doesn''t get eaten by $8 in gas fees.', 'Prediction Market', 'https://i.ibb.co/VppNgZkp/Modern-growth-logo-with-arc-and-bars-png.png', 'https://arcdict-markets.vercel.app/', '@hirnself', 'https://github.com/Emex111', NULL, '0x514098f3798c86d89fa2d36869fb372aaf1cbe54', FALSE, TRUE, TRUE, NULL, '"2026-04-14T15:35:12.450Z"', NULL, 'ndukwexcel@gmail.com', 'claimed', NULL, 20, 'arcdict-markets', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('103', 'Yieldra', 'The first autonomous credit and yield engine built for sub-cent AI agent settlements on the Arc Network.', 'Yieldra is a high-frequency credit and yield protocol built on the Arc. We introduce the H2A (Human-to-Agent) model, enabling humans to lend USDC directly to autonomous AI agents for on-chain work.', 'DeFi', 'https://i.ibb.co/Xk7L6mVg/Screenshot-31-png.png', 'https://yieldra-gamma.vercel.app/', '@Yieldrafi', 'https://github.com/tetheusz', NULL, '0xbdff90861346803250c8a4c8749627f4f90d42dc', FALSE, TRUE, TRUE, NULL, '"2026-04-20T12:44:10.833Z"', NULL, 'thetecoz@gmail.com', 'claimed', NULL, 6, 'yieldra', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('106', 'SPINARC', 'Fully Decentralized onchain Gaming.', 'Spinarc is a fully on-chain prediction game built on the ARC Network Testnet. Players pick a side Bull or Bear  place a USDC bet The outcome is determined by cryptographic randomness from multiple blockchain properties resolving itself in real time.', 'Gaming', 'https://i.ibb.co/277ChDsL/Spinarc-logo-png.png', 'https://spinarc.vercel.app', NULL, 'https://github.com/Elijah463', NULL, '0x2255e3b895a7602f8926061d6ceb25d27524e7d5', FALSE, TRUE, TRUE, NULL, '"2026-04-22T13:19:01.456Z"', NULL, 'eelijah463@gmail.com', 'claimed', NULL, 3, 'spinarc', '17a766f5baefa412826cb2b38d19f59ab89817b3513f6620e73b6f3ff73f2a5f', '"2026-04-22T20:33:56.622Z"', NULL, 'eelijah463@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('39', 'SWAPARC', 'A Stablecoin Swap Protocol/Privacy Payments System', 'Swaparc is a non-custodial stablecoin swap protocol built on the Arc blockchain, enabling fast, on-chain FX swaps between stablecoins like USDC and EURC directly from your wallet through liquidity pools. It offers seamless, transparent trading with features like slippage protection, persistent user profiles, real-time stats, and community badges for active Swaparcer participants. Designed for efficient stablecoin-native finance, Swaparc delivers low-cost, deterministic settlement in the Arc ecosystem.  ARCPAY, the upcoming privacy payments feature, will add auditable privacy controls for confidential yet compliant transactions—perfect for sensitive payments while maintaining full on-chain transparency where needed.', 'DeFi', 'https://i.ibb.co/k2wWxn5L/1001363613-jpg.jpg', 'https://www.swaparc.app/', '@swaparc_app', 'https://github.com/Somtiee/swaparc', 'Soon', '0x2f4490e7c6f3dac23ffee6e71bfcb5d1ccd7d4ec', FALSE, TRUE, TRUE, NULL, '"2026-04-06T09:51:26.887Z"', NULL, 'Somtochukwuogodinma@gmail.com', 'claimed', NULL, 179, 'swaparc', '6dd5a9e09c276703e717ff0b6e4f9a45ff61d3decfce35876f09b933180a85f4', '"2026-04-06T21:21:48.717Z"', '"2026-04-06T20:52:02.329Z"', 'somtochukwuogodinma@gmail.com', '0xd4d3e342902766344075d06c94391e61a9bb7e60', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('100', 'Doge forge', 'Mine fDOGE. Trade on Arc. Build your identity.', 'DOGE FORGE is a mining-first token protocol built on Arc Network. The core idea: you commit USDC, and that USDC converts continuously into fDOGE rewards. There is no staking mechanism, no lock period, and no yield farming. The conversion runs on pure math inside the Miner smart contract.', 'Infrastructure', 'https://i.ibb.co/b5mkZVz5/pfp-png.png', 'https://dogeforge.fun/', 'x.com/DogeForgefun', NULL, NULL, '0x25497e0ac492b79a3781fed41762f106f9158f71', FALSE, TRUE, TRUE, NULL, '"2026-04-19T04:08:52.605Z"', NULL, 'roisx00@gmail.com', 'claimed', NULL, 8, 'doge-forge', 'b20e466d5fc55f7dd3bfd488ec93cf47f47c772acb23ddca36be17f8732eb5b9', '"2026-04-20T14:54:41.765Z"', '"2026-04-20T14:24:53.152Z"', 'roisx00@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('8', 'Arc', 'The Economic OS for the Internet', 'Arc is Circle''s Layer-1 blockchain built for global financial applications. Sub-second finality, USDC as native gas, opt-in privacy, and deep integration with Circle''s full platform. Built for payments, FX, lending, and capital markets.', 'Infrastructure', 'https://i.ibb.co/2wMkfPT/arc-jpg.jpg', 'https://arc.network', 'https://x.com/arc', 'https://github.com/circlefin', 'https://discord.com/invite/buildonarc', NULL, TRUE, TRUE, TRUE, NULL, '"2026-03-30T19:45:52.712Z"', NULL, 'arclensdev@gmail.com', 'official', NULL, 154, 'arc', 'f27e31e962fd720c4487477d71790c9feca06bf6f9096245238b35cef3017e4d', '"2026-04-06T21:11:31.929Z"', '"2026-04-05T12:38:32.420Z"', 'arclensdev@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('104', 'Finity Market', 'NFT marketplace & launchpad on Arc. Built for finality.', 'Finity is the NFT marketplace and launchpad  on the Arc blockchain. \nBuilt for sub second finality and USDC native trading. \nFeatures include NFT trading, collection launchpad, and an on chain rewards system. Currently in development ahead of Arc mainnet launch.', 'NFT', 'https://i.ibb.co/3YcQd7dt/F-1-png.png', NULL, 'FinityMarket', NULL, NULL, NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-20T21:23:29.421Z"', NULL, 'finitymarketxyz@gmail.com', 'claimed', NULL, 2, 'finity-market', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('23', 'UnitFlow Finance', 'The Modern DeFi Hub - Trade, Build, Earn.', 'UnitFlow Finance is a next-generation decentralised exchange built on Arc. Our goal is straightforward: make on-chain trading feel as natural as anything in traditional finance, without sacrificing the permissionless, self-custodial nature that makes DeFi worth using. We do this through a combination of smart AMM infrastructure, AI-assisted execution, and a full suite of DeFi tools built into one platform.', 'DeFi', 'https://i.ibb.co/hRZpGGPZ/1001685288-jpg.jpg', 'https://www.unitflow.finance/', '@unitflowfinance', NULL, 'https://discord.gg/e3ddAUGcH', NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-01T17:07:33.824Z"', NULL, 'Steven@unitflow.finance', 'verified', NULL, 283, 'unitflow-finance', '1dd114604ca61076f75ffd93a49dbbb03fe56df2005f5c4aec187f2eb4421b6f', '"2026-04-12T09:30:21.301Z"', '"2026-04-12T09:00:48.386Z"', 'steven@unitflow.finance', '0x3682652cd0995e6972ccf7245a1caea95c2955b8', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('42', 'MirtanaProtocol', 'Mirtana Protocol: Web3 This is a decentralized application (DApp) designed for comprehensive token lifecycle management and blockchain interaction. The application features a futuristic design with an emphasis on speed, security, and user experience.', 'Mirtana Protocol is a multifunctional Web3 platform that provides users with a comprehensive set of tools for managing assets on the Arc network. The project integrates several key areas of decentralized finance (DeFi):\n\nToken Lifecycle Management: The built-in Token Factory allows users without programming skills to deploy their own ERC-20 smart contracts, manage their issuance, and track them through a personal dashboard.\n\nStaking and Loyalty: The platform offers mechanisms for holding assets to earn rewards, as well as a unique Daily GM system that encourages regular user interaction with the blockchain.\n\nSecurity and UX: The project focuses on an intuitive user experience with automatic network permission checks (Approve) and deep integration with blockchain explorers for transparent transaction tracking.\n\nThe project aims to simplify entry into the Web3 industry by providing all the necessary tools for creating, exchanging, and transferring digital assets in a single, high-tech interface.', 'DeFi', 'https://i.ibb.co/hFr1D44Z/MIRTAlogo-png.jpg', 'http//mirtana.github.io/Protocol/', '@MirtanaProtocol', 'https://github.com/Mirtana/Protocol', 'https://discord.gg/SdwEBqRrQj', '0xad4d6ed80f18768a1dde5f2b6a97a900a5c874e1', FALSE, TRUE, TRUE, NULL, '"2026-04-06T14:04:54.377Z"', NULL, 'mirtanaprotocol@gmail.com', 'claimed', NULL, 17, 'mirtanaprotocol', '3e1a530372d07cbc7fe166b115757c0468113617580f0888d090829e4bdf18a6', '"2026-04-06T16:47:57.442Z"', NULL, 'mirtanaprotocol@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('56', 'Archon', 'Multi-source onchain reputation platform built on Arc.', 'Archon is an Arc testnet dApp that turns real work into permanent onchain reputation by letting approved creators post paid tasks in USDC, contributors accept and submit deliverable links, creators review and approve with configurable rewards, and workers claim payout plus a credential that updates their score and tier.\n\nIt also supports agentic tasks for AI workflows, community credentials reviewed by named moderators, peer vouching with strict trust/anti-gaming rules, DAO governance vote credentials verified onchain, and milestone based smart contracts with escrow, auto-release, and arbitrator dispute resolution.', 'Other', 'https://i.ibb.co/KjCRpP2R/364353-png.png', 'https://archon-dapp.vercel.app', NULL, NULL, NULL, NULL, FALSE, TRUE, TRUE, NULL, '"2026-04-09T12:36:34.208Z"', NULL, 'abdulmalikabdulrashid1@gmail.com', 'claimed', NULL, 77, 'archon', '8df21882ce78d5443e25d4345032357859f3a2936a65df5f1c274c24e086339d', '"2026-04-11T08:41:21.510Z"', '"2026-04-09T16:46:24.500Z"', 'abdulmalikabdulrashid1@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('108', 'arc-ue4-plugin', 'An Unreal Engine plugin + Node.js backend that makes it easy to build onchain game flows on @Arc using familiar Blueprint nodes.', 'Read USDC balances inside Unreal (Blueprint-friendly)\n• Server-side USDC flows (payments/rewards) via Express + ethers v6\n• NFT mint flow via backend routes (returns tx hash / receipt)', 'Gaming', 'https://i.ibb.co/tPqsjJYL/174334-png.png', NULL, '@0xFawazdev', 'https://github.com/fawazdevx/arc-unreal-plugin', NULL, NULL, FALSE, FALSE, FALSE, NULL, '"2026-04-22T20:47:02.744Z"', NULL, 'oyebodefawaz2020@gmail.com', 'approved', NULL, 0, 'arc-ue4-plugin', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('24', 'Lunex', 'Curve-style StableSwap AMM optimised for USDC/EURC pairs with minimal slippage on Arc Network.', 'Lunex is a next-generation StableSwap AMM built on the Arc Network. We use a Curve-style invariant specifically optimized for high-efficiency, low-slippage trading between stablecoins, specifically USDC and EURC.\n\nLunex is designed for a variety of users:\n\nStablecoin Traders: Anyone looking to swap between USDC and EURC with minimal price impact (slippage).\n\nYield Seekers: Investors who want to earn passive income on their stablecoins through auto-compounding vaults.\n\nLiquidity Providers: Users who want to earn a share of trading fees by providing depth to our pools.\n\nDeFi Developers: Builders on the Arc Network who need a highly liquid, stable base-layer for their own applications.', 'DeFi', 'https://i.ibb.co/mCy38y5c/1001933064-jpg.jpg', 'https://lunexonarc.vercel.app/', '@lunexfinance', '', '', 'lunexlp token: 0x9fd18a3dcbcb8238f7426e888ba73affbf9f3b69, lunevault (usdc): 0x66cf9ca9d75fd62438c6e254ba35e61775ef9496, lunevault (eurc): 0xcf2c839b12ecf6d9eecd4607521b73fcfb7e8713', FALSE, TRUE, TRUE, NULL, '"2026-04-01T17:30:23.309Z"', '', 'lunexfinance@gmail.com', 'claimed', NULL, 36, 'lunex', '38d62e1f59be68547c6ead49ef411e35087f147f7cd5106b1f7f8fd3c22ac3e8', '"2026-04-07T07:55:50.840Z"', '"2026-04-07T01:38:38.881Z"', 'lunexfinance@gmail.com', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('107', 'Arc Drift', 'Payments made easier', 'Arc Drift is an onchain app for sending delayed or continuous USDC payments', 'Payments', 'https://i.ibb.co/jZzPpzGM/1002294075-png.png', 'https://arc-drift.vercel.app/', NULL, 'https://github.com/0xNexuz/arc-drifts', NULL, '0xca023e888478c8ada406b2dfaffc171da3d0ab73', FALSE, TRUE, TRUE, NULL, '"2026-04-22T18:25:22.741Z"', NULL, 'elllbest7@gmail.com', 'claimed', NULL, 0, 'arc-drift', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO projects (id, name, tagline, description, category, logo_url, website, twitter, github, discord, contract, featured, approved, live, launched_at, created_at, color, email, badge, social_proof, view_count, slug, claim_token, claim_token_expires, claimed_at, owner_email, owner_wallet, city, country, lat, lng) VALUES ('60', 'Arc Dungeons', 'A pixel-art survival game where players dodge enemies in on-chain dungeons, spend USDC to unlock harder levels, and compete for seasonal prize pool rewards on Arc Network.', 'Arc Dungeons is a pixel-art survival game on Arc Network where players dodge enemies in on-chain dungeons, spend USDC to unlock harder levels, and compete for seasonal prize pool rewards.\n\nPlayers connect their wallet, pick a dungeon, and try to survive as long as possible by dodging waves of enemies on a grid-based battlefield. The game has a retro aesthetic with CRT scanlines, neon glow effects, and screen shake on hits. Players can pause/resume and choose between Easy, Normal, and Hard difficulty modes. A live kill counter and run timer track performance.\n\nThree dungeons are available:\n- **Dark Forest** (free) - open to everyone\n- **Shadow Mines** - requires a Bronze Key + 0.5 USDC entry fee\n- **Frost Caverns** - requires a Silver Key + 1 USDC entry fee\n\nKeys and consumables (health potions, mana potions, revive scrolls, XP boosts) can be purchased from the in-game shop using USDC, with bundle discounts and a loyalty system.\n\nEvery run is registered on-chain before gameplay begins, so scores can''t be faked. Completed runs also generate randomized loot drops minted directly to the player''s wallet.\n\nSeasons run for 30 days. All entry fees accumulate into a USDC prize pool, and when the season ends the top 3 players on the leaderboard split it (50% / 30% / 20%).', 'Gaming', 'https://i.ibb.co/G3VHXDNJ/Screenshot-2026-04-09-174623-png.png', 'https://arcescape.vercel.app/', '@0xgiwa', 'https://github.com/giwaov/arc-dungeons', NULL, '0xf9fd51fe97b601f93f4857d1a40884530cbb15e5', FALSE, TRUE, TRUE, NULL, '"2026-04-09T17:04:21.841Z"', NULL, 'giwavictor9@gmail.com', 'claimed', NULL, 39, 'arc-dungeons', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
