INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (4, 49, '0x32f251fc36a1174901124589eac2d4e391816f69', 'Performance', 5, 'cool application can send to many addresses suitable for HR to pay salaries', TRUE, NULL, 'arc_user', '"2026-04-09T16:57:26.512Z"') ON CONFLICT DO NOTHING;
INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (5, 57, '0xef9cd31e430b014f4a6d29fc2220e2234d46378d', 'Product Experience', 5, 'Bug Report: Portfolio & Activity not displaying on-chain trades\n\nDescription:\nTrades made directly via smart contract (buyShares) are not showing in Portfolio or Activity page, even though transactions are confirmed on-chain.\n\nRoot Cause (identified):\nThe frontend queries ArcScan API with an unsupported limit parameter:\nGET https://testnet.arcscan.app/api/v2/addresses/0x443a47eF1025e047879b1BA08c94e6dedB354D54/token-transfers?token=0x3600000000000000000000000000000000000000&filter=to&limit=50ArcScan API v2 returns error:\n{"errors": [{"title": "Invalid value", "source": {"pointer": "/limit"}, "detail": "Unexpected field: limit"}]}Because the request fails, the frontend cannot fetch transaction history and displays "No trades yet."\n\nFix suggestion:\nRemove limit=50 parameter from the API call, or replace with the correct pagination parameter supported by ArcScan v2 (e.g. page_size or similar).\n\nVerification:\nWithout limit, the API works correctly:\nhttps://testnet.arcscan.app/api/v2/addresses/0x443a47eF1025e047879b1BA08c94e6dedB354D54/token-transfers?token=0x3600000000000000000000000000000000000000&filter=toAll on-chain trades are visible in the response.\n\nWallet: 0xA24689956Ea3Ae5E4ccEc37337B8B81Cf466ed43\nNetwork: Arc Testnet (Chain ID: 5042002)', TRUE, NULL, 'arc_user', '"2026-04-14T01:47:24.253Z"') ON CONFLICT DO NOTHING;
INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (6, 38, '0xf23690ada54d6b9351abdb31cbb2acd8cd0b7dfa', 'Product Experience', 5, 'Apexis DeFi strikes me as a project with a solid vision within the Web3 ecosystem. I appreciate that it doesn''t focus solely on swaps, but rather on building a complete infrastructure with tools like a DEX, an NFT marketplace, and on-chain analytics.\n\nThe interface looks modern and professional, and the focus on security and scalability inspires confidence. Although some features are still in beta, the project shows growth potential and a unique proposition within the DeFi sector.\n\nIt''s definitely a project worth keeping a close eye on.', TRUE, NULL, 'arc_user', '"2026-04-15T00:38:47.060Z"') ON CONFLICT DO NOTHING;
INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (7, 18, '0x38d5b552e7d83ee3b40cc99835bb33f29accf992', 'Product Experience', 4, 'The Ach Bridge stood out the most.\nBut I think “Remove Liquidity” shouldn’t be on a separate tab — it would feel smoother if it’s integrated directly into the Add Liquidity flow.', TRUE, 'thomasmykl4@gmail.com', 'arc_user', '"2026-04-17T23:08:13.820Z"') ON CONFLICT DO NOTHING;
