INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (10, 18, '0x847c5c6e74b0cc2c054af61efc153a4492bfd930', 'UI/UX', 5, 'ACH SWAP的整体体验超出预期！兑换、添加/移除流动性、跨链桥接这些核心功能都稳定又好用，控制面板设计得很直观，新手也能快速上手。交易执行高效，预测市场的界面也很简洁，加上丰富的链上资产支持，实用性拉满。', TRUE, 'tan_gzaiqing@126.com', 'arc_user', '"2026-04-20T08:50:40.194Z"') ON CONFLICT DO NOTHING;
INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (11, 39, '0x847c5c6e74b0cc2c054af61efc153a4492bfd930', 'Product Experience', 5, 'The overall interaction is very smooth, but it would be better to change the "Website" section to "Swap" for easier distinction!', TRUE, 'tan_gzaiqing@126.com', 'arc_user', '"2026-04-20T09:54:31.557Z"') ON CONFLICT DO NOTHING;
