INSERT INTO reviews (id, project_id, wallet, category, rating, review_text, is_public, contact, badge, created_at) VALUES (13, 39, '0x38d5b552e7d83ee3b40cc99835bb33f29accf992', 'UI/UX', 5, 'This is a strong project bringing real Web2-like experience on-chain fast, convenient, and user-friendly.\n\nEasy 10/10 for UI/UX from me.\n\nDropped 5⭐and I’m especially looking forward to using the bills payment feature more on swaparc', TRUE, NULL, 'arc_user', '"2026-04-20T17:56:46.054Z"') ON CONFLICT DO NOTHING;
