INSERT INTO contracts (address, name, type, description, logo_url, website, twitter, github, audit_url, source_code, verified, flagged, flag_reason, verified_at, created_at, updated_at, deployer, tx_count, unique_users, badge, email) VALUES ('0x57d744969597cc1c4dab8f4db8deb27c23078ed8', 'MaisonPerp', 'DEX', 'Core perpetual futures engine. Handles opening/closing leveraged positions (up to 25x) on BTC, ETH, SOL, EURC, BRLA and MXNB. Uses a pull oracle with signed prices, charges 0.1% open/close fees, enforces 5% maintenance margin, and emits events consumed by the social copy-trading layer.', NULL, 'https://maison.up.railway.app', NULL, NULL, NULL, '// SPDX-License-Identifier: MIT\npragma solidity ^0.8.24;\n\n// src/interfaces/IArcUSDC.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// IArcUSDC\n//\n// Arc testnet USDC ERC-20 interface.\n// Address: 0x3600000000000000000000000000000000000000\n//\n// CRITICAL Arc-specific notes:\n//   - Native USDC gas balance uses 18 decimals (like ETH on Ethereum)\n//   - The ERC-20 interface (this file) uses 6 decimals\n//   - ALWAYS use the ERC-20 interface for token transfers and allowances\n//   - NEVER mix native balance (18 dec) with ERC-20 amounts (6 dec)\n//   - 1 USDC = 1_000_000 in ERC-20 units (6 decimals)\n// ─────────────────────────────────────────────────────────────────────────────\n\ninterface IArcUSDC {\n    // ── ERC-20 standard ──────────────────────────────────────────────────────\n    function totalSupply() external view returns (uint256);\n    function balanceOf(address account) external view returns (uint256);\n    function transfer(address to, uint256 amount) external returns (bool);\n    function allowance(address owner, address spender) external view returns (uint256);\n    function approve(address spender, uint256 amount) external returns (bool);\n    function transferFrom(address from, address to, uint256 amount) external returns (bool);\n\n    // ── Metadata ─────────────────────────────────────────────────────────────\n    function decimals() external view returns (uint8);   // returns 6\n    function symbol() external view returns (string memory);\n    function name() external view returns (string memory);\n\n    // ── Events ───────────────────────────────────────────────────────────────\n    event Transfer(address indexed from, address indexed to, uint256 value);\n    event Approval(address indexed owner, address indexed spender, uint256 value);\n}\n\n// src/MaisonPullOracle.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// MaisonPullOracle\n//\n// Pull-based oracle for MAISON on Arc testnet.\n// Prices are signed offchain by a trusted signer and submitted by the user\n// AT THE TIME of their transaction. Zero staleness possible.\n//\n// How it works:\n//   1. Offchain signer (Node.js) pulls price from Binance every 500ms\n//   2. Signer signs: keccak256(asset, price, timestamp)\n//   3. Signature is cached in the frontend\n//   4. When trader opens/closes, they include the signed price in their tx\n//   5. This contract verifies the signature onchain using ecrecover\n//   6. If valid and fresh (< MAX_AGE seconds), price is accepted\n//   7. If invalid or stale, entire transaction reverts\n//\n// Price precision: 6 decimals (matches USDC)\n//   BTC at $97,420 = 97_420_000_000\n// ─────────────────────────────────────────────────────────────────────────────\n\ncontract MaisonPullOracle {\n\n    // ── Constants ─────────────────────────────────────────────────────────────\n    uint256 public constant MAX_AGE        = 120;  // seconds — max price age\n    uint256 public constant PRICE_DECIMALS = 6;   // matches USDC\n\n    // ── State ─────────────────────────────────────────────────────────────────\n    address public owner;\n    address public trustedSigner; // only this address can sign valid prices\n\n    // Cache last accepted price per asset (for liquidation keeper reads)\n    struct CachedPrice {\n        uint256 price;\n        uint256 timestamp;\n    }\n    mapping(bytes32 => CachedPrice) public lastAccepted;\n\n    // ── Asset keys — must match signer and MaisonPerp ─────────────────────────\n    bytes32 public constant BTC  = keccak256("BTC");\n    bytes32 public constant ETH  = keccak256("ETH");\n    bytes32 public constant SOL  = keccak256("SOL");\n    bytes32 public constant EURC = keccak256("EURC");\n    bytes32 public constant BRLA = keccak256("BRLA");\n    bytes32 public constant MXNB = keccak256("MXNB");\n\n    // ── Events ────────────────────────────────────────────────────────────────\n    event PriceAccepted(bytes32 indexed asset, uint256 price, uint256 timestamp);\n    event SignerUpdated(address indexed oldSigner, address indexed newSigner);\n\n    // ── Structs ───────────────────────────────────────────────────────────────\n\n    // This is what gets passed in every trade transaction\n    struct SignedPrice {\n        bytes32 asset;      // keccak256("BTC") etc\n        uint256 price;      // 6 decimal precision\n        uint256 timestamp;  // unix timestamp when signer signed this\n        bytes   signature;  // 65-byte ECDSA signature\n    }\n\n    // ── Constructor ──────────────────────────────────────────────────────────\n    constructor(address _trustedSigner) {\n        require(_trustedSigner != address(0), "Oracle: zero signer");\n        owner         = msg.sender;\n        trustedSigner = _trustedSigner;\n    }\n\n    // ── Modifiers ─────────────────────────────────────────────────────────────\n    modifier onlyOwner() {\n        require(msg.sender == owner, "Oracle: not owner");\n        _;\n    }\n\n    // ── Core: verify and return price ─────────────────────────────────────────\n\n    /// @notice Verify a signed price and return it if valid\n    /// @dev Called internally by MaisonPerp on every open/close/liquidate\n    /// @param sp The signed price struct submitted by the user\n    /// @return price The verified price (6 decimals)\n    function verifyAndGetPrice(SignedPrice calldata sp)\n        external\n        returns (uint256 price)\n    {\n        // ── 1. Check price is fresh ───────────────────────────────────────────\n        require(sp.timestamp > 0, "Oracle: zero timestamp");\n        require(\n            block.timestamp <= sp.timestamp + MAX_AGE,\n            "Oracle: price too old"\n        );\n        require(\n            sp.timestamp <= block.timestamp + 5, // allow 5s clock drift\n            "Oracle: price from future"\n        );\n\n        // ── 2. Reconstruct the message the signer signed ──────────────────────\n        // Must exactly match what the offchain signer signs\n        bytes32 messageHash = _buildMessageHash(sp.asset, sp.price, sp.timestamp);\n\n        // ── 3. Recover signer from signature ──────────────────────────────────\n        address recovered = _recoverSigner(messageHash, sp.signature);\n        require(recovered == trustedSigner, "Oracle: invalid signature");\n\n        // ── 4. Sanity check price is non-zero ─────────────────────────────────\n        require(sp.price > 0, "Oracle: zero price");\n\n        // ── 5. Cache the accepted price ───────────────────────────────────────\n        // Liquidation keeper can read this without needing a signature\n        lastAccepted[sp.asset] = CachedPrice({\n            price:     sp.price,\n            timestamp: sp.timestamp\n        });\n\n        emit PriceAccepted(sp.asset, sp.price, sp.timestamp);\n\n        return sp.price;\n    }\n\n    /// @notice Read-only verify — does not update cache, for view calls\n    function verifyPrice(SignedPrice calldata sp) external view returns (uint256) {\n        require(block.timestamp <= sp.timestamp + MAX_AGE, "Oracle: price too old");\n        require(sp.timestamp <= block.timestamp + 5, "Oracle: price from future");\n\n        bytes32 messageHash = _buildMessageHash(sp.asset, sp.price, sp.timestamp);\n        address recovered   = _recoverSigner(messageHash, sp.signature);\n        require(recovered == trustedSigner, "Oracle: invalid signature");\n        require(sp.price > 0, "Oracle: zero price");\n\n        return sp.price;\n    }\n\n    /// @notice Get last cached price (for liquidation keeper / UI reads)\n    /// @dev This is NOT verified — use only for display and liquidation checks\n    ///      The keeper will always submit a fresh signed price when liquidating\n    function getLastPrice(bytes32 asset) external view returns (uint256 price, uint256 timestamp) {\n        CachedPrice memory cp = lastAccepted[asset];\n        return (cp.price, cp.timestamp);\n    }\n\n    /// @notice Check if cached price is still within acceptable age\n    function isCachedFresh(bytes32 asset) external view returns (bool) {\n        CachedPrice memory cp = lastAccepted[asset];\n        if (cp.timestamp == 0) return false;\n        return block.timestamp <= cp.timestamp + MAX_AGE;\n    }\n\n    // ── Signature helpers ─────────────────────────────────────────────────────\n\n    /// @notice Build the message hash that the offchain signer must sign\n    /// @dev MUST match exactly what the Node.js signer produces\n    ///      Format: "\x19Ethereum Signed Message:\n32" + keccak256(asset, price, timestamp)\n    function _buildMessageHash(\n        bytes32 asset,\n        uint256 price,\n        uint256 timestamp\n    ) internal pure returns (bytes32) {\n        // Inner hash: tightly packed encoding of the price data\n        bytes32 dataHash = keccak256(abi.encodePacked(\n            asset,\n            price,\n            timestamp\n        ));\n\n        // Ethereum signed message prefix (EIP-191 personal_sign format)\n        // This matches ethers.js signMessage() behaviour\n        return keccak256(abi.encodePacked(\n            "\x19Ethereum Signed Message:\n32",\n            dataHash\n        ));\n    }\n\n    /// @notice Recover signer address from message hash and signature\n    function _recoverSigner(\n        bytes32 messageHash,\n        bytes memory signature\n    ) internal pure returns (address) {\n        require(signature.length == 65, "Oracle: bad signature length");\n\n        bytes32 r;\n        bytes32 s;\n        uint8   v;\n\n        assembly {\n            r := mload(add(signature, 32))\n            s := mload(add(signature, 64))\n            v := byte(0, mload(add(signature, 96)))\n        }\n\n        // Normalise v (some signers return 0/1, EVM expects 27/28)\n        if (v < 27) v += 27;\n        require(v == 27 || v == 28, "Oracle: invalid v");\n\n        address recovered = ecrecover(messageHash, v, r, s);\n        require(recovered != address(0), "Oracle: ecrecover failed");\n\n        return recovered;\n    }\n\n    // ── Owner ─────────────────────────────────────────────────────────────────\n\n    /// @notice Rotate the trusted signer key\n    function setSigner(address newSigner) external onlyOwner {\n        require(newSigner != address(0), "Oracle: zero address");\n        emit SignerUpdated(trustedSigner, newSigner);\n        trustedSigner = newSigner;\n    }\n\n    function transferOwnership(address newOwner) external onlyOwner {\n        require(newOwner != address(0), "Oracle: zero address");\n        owner = newOwner;\n    }\n\n    // ── View: build message hash for offchain signing ─────────────────────────\n\n    /// @notice Helper for the offchain signer to verify it''s hashing correctly\n    function buildMessageHash(\n        bytes32 asset,\n        uint256 price,\n        uint256 timestamp\n    ) external pure returns (bytes32) {\n        return _buildMessageHash(asset, price, timestamp);\n    }\n}\n\n// src/MaisonVault.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// MaisonVault\n//\n// Holds all trader USDC margin on Arc testnet.\n// All amounts in USDC ERC-20 units (6 decimals).\n//\n// Arc-specific: uses USDC ERC-20 at 0x3600000000000000000000000000000000000000\n// NEVER interact with native Arc balance — always use the ERC-20 interface.\n//\n// Architecture:\n//   - Traders deposit USDC → credited as free margin\n//   - PositionManager locks margin when a position opens\n//   - PositionManager releases/adjusts margin when position closes\n//   - SocialLayer reads balances for copy fee payments\n// ─────────────────────────────────────────────────────────────────────────────\n\ncontract MaisonVault {\n\n    // ── Arc testnet USDC ERC-20 (6 decimals) ─────────────────────────────────\n    address  public constant USDC_ADDRESS = 0x3600000000000000000000000000000000000000;\n\n    // ── Access control ────────────────────────────────────────────────────────\n    address public owner;\n    address public positionManager;  // only contract that can lock/unlock margin\n    address public socialLayer;      // only contract that can pay copy fees\n\n    // ── Margin accounting ─────────────────────────────────────────────────────\n    // All values in USDC with 6 decimals\n\n    mapping(address => uint256) public freeMargin;   // available to open positions\n    mapping(address => uint256) public lockedMargin; // locked in open positions\n    mapping(address => uint256) public copyEarnings; // accumulated copy fees earned\n\n    // ── Protocol fee collection ───────────────────────────────────────────────\n    uint256 public protocolFees; // total accumulated, claimable by owner\n\n    // ── Events ────────────────────────────────────────────────────────────────\n    event Deposited(address indexed trader, uint256 amount);\n    event Withdrawn(address indexed trader, uint256 amount);\n    event MarginLocked(address indexed trader, uint256 amount, uint256 positionId);\n    event MarginReleased(address indexed trader, uint256 amount, uint256 positionId);\n    event MarginLiquidated(address indexed trader, uint256 amount, uint256 positionId);\n    event CopyFeeEarned(address indexed leader, uint256 amount);\n    event CopyFeePaid(address indexed copier, uint256 amount);\n    event CopyEarningsClaimed(address indexed leader, uint256 amount);\n    event ProtocolFeeCollected(uint256 amount);\n\n    // ── Constructor ──────────────────────────────────────────────────────────\n    constructor() {\n        owner = msg.sender;\n    }\n\n    // ── USDC getter — virtual so tests can inject a mock ─────────────────────\n    function getUSDC() internal view virtual returns (IArcUSDC) {\n        return IArcUSDC(USDC_ADDRESS);\n    }\n\n    // ── Access modifiers ──────────────────────────────────────────────────────\n    modifier onlyOwner() {\n        require(msg.sender == owner, "Vault: not owner");\n        _;\n    }\n\n    modifier onlyPositionManager() {\n        require(msg.sender == positionManager, "Vault: not position manager");\n        _;\n    }\n\n    modifier onlySocialLayer() {\n        require(msg.sender == socialLayer, "Vault: not social layer");\n        _;\n    }\n\n    modifier onlyAuthorized() {\n        require(\n            msg.sender == positionManager || msg.sender == socialLayer,\n            "Vault: not authorized"\n        );\n        _;\n    }\n\n    // ── Setup ─────────────────────────────────────────────────────────────────\n\n    function setPositionManager(address _pm) external onlyOwner {\n        require(_pm != address(0), "Vault: zero address");\n        positionManager = _pm;\n    }\n\n    function setSocialLayer(address _sl) external onlyOwner {\n        require(_sl != address(0), "Vault: zero address");\n        socialLayer = _sl;\n    }\n\n    function transferOwnership(address newOwner) external onlyOwner {\n        require(newOwner != address(0), "Vault: zero address");\n        owner = newOwner;\n    }\n\n    // ── Trader-facing ─────────────────────────────────────────────────────────\n\n    /// @notice Deposit USDC margin\n    /// @dev Trader must approve this contract first: USDC.approve(vault, amount)\n    /// @param amount Amount in USDC ERC-20 units (6 decimals). 100 USDC = 100_000_000\n    function deposit(uint256 amount) external {\n        require(amount > 0, "Vault: zero amount");\n\n        // Pull USDC from trader — uses ERC-20 transferFrom (6 decimals)\n        bool success = getUSDC().transferFrom(msg.sender, address(this), amount);\n        require(success, "Vault: USDC transfer failed");\n\n        freeMargin[msg.sender] += amount;\n\n        emit Deposited(msg.sender, amount);\n    }\n\n    /// @notice Withdraw free margin (not locked in positions)\n    function withdraw(uint256 amount) external {\n        require(amount > 0, "Vault: zero amount");\n        require(freeMargin[msg.sender] >= amount, "Vault: insufficient free margin");\n\n        freeMargin[msg.sender] -= amount;\n\n        bool success = getUSDC().transfer(msg.sender, amount);\n        require(success, "Vault: USDC transfer failed");\n\n        emit Withdrawn(msg.sender, amount);\n    }\n\n    /// @notice Claim accumulated copy earnings\n    function claimCopyEarnings() external {\n        uint256 earnings = copyEarnings[msg.sender];\n        require(earnings > 0, "Vault: no earnings");\n\n        copyEarnings[msg.sender] = 0;\n\n        bool success = getUSDC().transfer(msg.sender, earnings);\n        require(success, "Vault: USDC transfer failed");\n\n        emit CopyEarningsClaimed(msg.sender, earnings);\n    }\n\n    // ── PositionManager-facing ────────────────────────────────────────────────\n\n    /// @notice Lock margin when a position opens\n    function lockMargin(address trader, uint256 amount, uint256 positionId) external onlyPositionManager {\n        require(freeMargin[trader] >= amount, "Vault: insufficient margin");\n\n        freeMargin[trader]  -= amount;\n        lockedMargin[trader] += amount;\n\n        emit MarginLocked(trader, amount, positionId);\n    }\n\n    /// @notice Release locked margin back to free (position closed with PnL applied)\n    /// @param pnl Signed PnL — positive means trader profited, negative means loss\n    function releaseMargin(\n        address trader,\n        uint256 lockedAmount,\n        int256  pnl,\n        uint256 positionId\n    ) external onlyPositionManager {\n        require(lockedMargin[trader] >= lockedAmount, "Vault: margin accounting error");\n\n        lockedMargin[trader] -= lockedAmount;\n\n        if (pnl >= 0) {\n            // Profitable — return locked margin + profit\n            uint256 profit = uint256(pnl);\n            freeMargin[trader] += lockedAmount + profit;\n        } else {\n            // Loss — deduct from locked margin\n            uint256 loss = uint256(-pnl);\n            if (loss >= lockedAmount) {\n                // Full wipeout — trader loses entire margin for this position\n                // Remainder goes to insurance fund (protocol fees)\n                protocolFees += lockedAmount;\n            } else {\n                freeMargin[trader] += lockedAmount - loss;\n                protocolFees += loss; // loss goes to protocol/insurance\n            }\n        }\n\n        emit MarginReleased(trader, lockedAmount, positionId);\n    }\n\n    /// @notice Liquidate a position — locked margin goes to insurance fund\n    function liquidate(address trader, uint256 lockedAmount, uint256 positionId) external onlyPositionManager {\n        require(lockedMargin[trader] >= lockedAmount, "Vault: margin accounting error");\n\n        lockedMargin[trader] -= lockedAmount;\n        protocolFees += lockedAmount; // liquidated margin to insurance fund\n\n        emit MarginLiquidated(trader, lockedAmount, positionId);\n    }\n\n    // ── SocialLayer-facing ────────────────────────────────────────────────────\n\n    /// @notice Pay copy fee: deduct from copier''s free margin, credit to leader\n    /// @param copier  The trader who copied\n    /// @param leader  The trader who posted the position\n    /// @param totalFee Total fee amount (split between leader and protocol)\n    /// @param leaderShare Amount going to leader (rest goes to protocol)\n    function payCopyFee(\n        address copier,\n        address leader,\n        uint256 totalFee,\n        uint256 leaderShare\n    ) external onlySocialLayer {\n        require(freeMargin[copier] >= totalFee, "Vault: copier insufficient margin for fee");\n        require(leaderShare <= totalFee, "Vault: leader share exceeds total fee");\n\n        uint256 protocolShare = totalFee - leaderShare;\n\n        freeMargin[copier]    -= totalFee;\n        copyEarnings[leader]  += leaderShare;\n        protocolFees          += protocolShare;\n\n        emit CopyFeeEarned(leader, leaderShare);\n        emit CopyFeePaid(copier, totalFee);\n        emit ProtocolFeeCollected(protocolShare);\n    }\n\n    // ── Owner ─────────────────────────────────────────────────────────────────\n\n    /// @notice Withdraw accumulated protocol fees\n    function withdrawProtocolFees(address to) external onlyOwner {\n        require(protocolFees > 0, "Vault: no fees");\n        uint256 amount = protocolFees;\n        protocolFees = 0;\n        bool success = getUSDC().transfer(to, amount);\n        require(success, "Vault: transfer failed");\n    }\n\n    // ── Views ─────────────────────────────────────────────────────────────────\n\n    /// @notice Total margin (free + locked) for a trader\n    function totalMargin(address trader) external view returns (uint256) {\n        return freeMargin[trader] + lockedMargin[trader];\n    }\n\n    /// @notice Total USDC held in this vault (sanity check)\n    function totalUSDCHeld() external view returns (uint256) {\n        return getUSDC().balanceOf(address(this));\n    }\n}\n\n// src/MaisonPerp.sol\n\ninterface IMaisonSocial {\n    function onPositionClosed(uint256 positionId, int256 realisedPnl, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata signedPrice) external;\n}\n\ncontract MaisonPerp {\n\n    uint256 private _status = 1;\n    modifier nonReentrant() {\n        require(_status == 1, "Perp: reentrant call");\n        _status = 2;\n        _;\n        _status = 1;\n    }\n\n    uint256 public constant BASIS_POINTS    = 10_000;\n    uint256 public constant MAX_LEVERAGE    = 25;\n    uint256 public constant MIN_LEVERAGE    = 1;\n    uint256 public constant FUNDING_INTERVAL = 8 hours;\n    uint256 public constant FUNDING_RATE_MAX = 100;\n    uint256 public constant MAINT_MARGIN_BPS = 500;\n    uint256 public constant LIQ_FEE_BPS     = 100;\n    uint256 public constant OPEN_FEE_BPS    = 10;\n    uint256 public constant CLOSE_FEE_BPS   = 10;\n    uint256 public constant INSURANCE_SHARE = 2000;\n\n    MaisonVault      public immutable vault;\n    MaisonPullOracle public immutable oracle;\n    address          public owner;\n    address          public socialLayer;\n    uint256          public insuranceFund;\n    uint256          public nextPositionId = 1;\n\n    enum Direction { LONG, SHORT }\n    enum Status    { OPEN, CLOSED, LIQUIDATED }\n\n    struct Position {\n        uint256   id;\n        address   trader;\n        bytes32   asset;\n        Direction direction;\n        uint256   size;\n        uint256   margin;\n        uint256   leverage;\n        uint256   entryPrice;\n        uint256   openTimestamp;\n        uint256   lastFundingTimestamp;\n        int256    accruedFunding;\n        Status    status;\n        bool      isPublic;\n        int256    realisedPnl;\n        uint256   takeProfitPrice;\n        uint256   stopLossPrice;\n    }\n\n    mapping(uint256 => Position)   public positions;\n    mapping(address => uint256[])  public traderPositions;\n    uint256[]                      public openPositionIds;\n    mapping(uint256 => uint256)    private _openPositionIndex;\n\n    struct Market {\n        bytes32 asset;\n        uint256 totalLongSize;\n        uint256 totalShortSize;\n        uint256 lastFundingTime;\n        int256  cumulativeFundingRate;\n        bool    active;\n    }\n\n    mapping(bytes32 => Market) public markets;\n    bytes32[]                  public activeMarkets;\n\n    event PositionOpened(uint256 indexed positionId, address indexed trader, bytes32 indexed asset, Direction direction, uint256 size, uint256 margin, uint256 leverage, uint256 entryPrice, bool isPublic);\n    event PositionClosed(uint256 indexed positionId, address indexed trader, uint256 exitPrice, int256 pnl, uint256 fee);\n    event PositionLiquidated(uint256 indexed positionId, address indexed trader, address indexed liquidator, uint256 markPrice, uint256 marginLost);\n    event TakeProfitTriggered(uint256 indexed positionId, uint256 exitPrice);\n    event StopLossTriggered(uint256 indexed positionId, uint256 exitPrice);\n    event TPSLUpdated(uint256 indexed positionId, uint256 tpPrice, uint256 slPrice);\n    event FundingSettled(bytes32 indexed asset, int256 fundingRate, uint256 timestamp);\n    event InsuranceFundUpdated(uint256 newBalance);\n    event MarketActivated(bytes32 indexed asset);\n\n    constructor(address _vault, address _oracle) {\n        vault  = MaisonVault(_vault);\n        oracle = MaisonPullOracle(_oracle);\n        owner  = msg.sender;\n        _activateMarket(keccak256("BTC"));\n        _activateMarket(keccak256("ETH"));\n        _activateMarket(keccak256("SOL"));\n        _activateMarket(keccak256("EURC"));\n        _activateMarket(keccak256("BRLA"));\n        _activateMarket(keccak256("MXNB"));\n    }\n\n    modifier onlyOwner() { require(msg.sender == owner, "Perp: not owner"); _; }\n    modifier onlySocialLayer() { require(msg.sender == socialLayer, "Perp: not social layer"); _; }\n    modifier positionExists(uint256 id) { require(positions[id].id == id, "Perp: not found"); _; }\n    modifier positionOpen(uint256 id) { require(positions[id].status == Status.OPEN, "Perp: not open"); _; }\n\n    function setSocialLayer(address _sl) external onlyOwner { socialLayer = _sl; }\n    function transferOwnership(address n) external onlyOwner { owner = n; }\n\n    // ── Open ──────────────────────────────────────────────────────────────────\n\n    function openPositionWithPrice(\n        bytes32 asset, Direction direction, uint256 margin, uint256 leverage, bool isPublic,\n        MaisonPullOracle.SignedPrice calldata sp\n    ) external nonReentrant returns (uint256) {\n        return _openPosition(msg.sender, asset, direction, margin, leverage, isPublic, oracle.verifyAndGetPrice(sp));\n    }\n\n    function openCopyPosition(\n        address copier, bytes32 asset, Direction direction, uint256 margin, uint256 leverage,\n        MaisonPullOracle.SignedPrice calldata sp\n    ) external onlySocialLayer nonReentrant returns (uint256) {\n        return _openPosition(copier, asset, direction, margin, leverage, false, oracle.verifyAndGetPrice(sp));\n    }\n\n    function _openPosition(address trader, bytes32 asset, Direction direction, uint256 margin, uint256 leverage, bool isPublic, uint256 entryPrice) internal returns (uint256 positionId) {\n        require(markets[asset].active,                                "Perp: market not active");\n        require(leverage >= MIN_LEVERAGE && leverage <= MAX_LEVERAGE, "Perp: invalid leverage");\n        require(margin > 0,                                           "Perp: zero margin");\n        require(entryPrice > 0,                                       "Perp: zero price");\n        require(vault.freeMargin(trader) >= margin,                   "Perp: insufficient margin");\n\n        uint256 size    = margin * leverage;\n        uint256 openFee = (size * OPEN_FEE_BPS) / BASIS_POINTS;\n        require(vault.freeMargin(trader) >= margin + openFee, "Perp: insufficient margin for fee");\n\n        _settleFunding(asset);\n        if (direction == Direction.LONG) markets[asset].totalLongSize  += size;\n        else                             markets[asset].totalShortSize += size;\n\n        positionId = nextPositionId++;\n        vault.lockMargin(trader, margin + openFee, positionId);\n\n        uint256 ins = (openFee * INSURANCE_SHARE) / BASIS_POINTS;\n        insuranceFund += ins;\n\n        positions[positionId] = Position({\n            id: positionId, trader: trader, asset: asset, direction: direction,\n            size: size, margin: margin, leverage: leverage, entryPrice: entryPrice,\n            openTimestamp: block.timestamp, lastFundingTimestamp: block.timestamp,\n            accruedFunding: 0, status: Status.OPEN, isPublic: isPublic,\n            realisedPnl: 0, takeProfitPrice: 0, stopLossPrice: 0\n        });\n\n        traderPositions[trader].push(positionId);\n        openPositionIds.push(positionId);\n        _openPositionIndex[positionId] = openPositionIds.length - 1;\n        emit PositionOpened(positionId, trader, asset, direction, size, margin, leverage, entryPrice, isPublic);\n        return positionId;\n    }\n\n    // ── TP/SL ─────────────────────────────────────────────────────────────────\n\n    function setTPSL(uint256 positionId, uint256 tpPrice, uint256 slPrice)\n        external positionExists(positionId) positionOpen(positionId)\n    {\n        Position storage pos = positions[positionId];\n        require(pos.trader == msg.sender, "Perp: not your position");\n        if (tpPrice > 0) {\n            if (pos.direction == Direction.LONG)  require(tpPrice > pos.entryPrice, "Perp: TP above entry for long");\n            else                                  require(tpPrice < pos.entryPrice, "Perp: TP below entry for short");\n        }\n        if (slPrice > 0) {\n            if (pos.direction == Direction.LONG)  require(slPrice < pos.entryPrice, "Perp: SL below entry for long");\n            else                                  require(slPrice > pos.entryPrice, "Perp: SL above entry for short");\n        }\n        pos.takeProfitPrice = tpPrice;\n        pos.stopLossPrice   = slPrice;\n        emit TPSLUpdated(positionId, tpPrice, slPrice);\n    }\n\n    function triggerTPSL(uint256 positionId, MaisonPullOracle.SignedPrice calldata sp)\n        external nonReentrant positionExists(positionId) positionOpen(positionId)\n    {\n        uint256 markPrice = oracle.verifyAndGetPrice(sp);\n        Position storage pos = positions[positionId];\n\n        bool tpHit = pos.takeProfitPrice > 0 && (\n            (pos.direction == Direction.LONG  && markPrice >= pos.takeProfitPrice) ||\n            (pos.direction == Direction.SHORT && markPrice <= pos.takeProfitPrice)\n        );\n        bool slHit = pos.stopLossPrice > 0 && (\n            (pos.direction == Direction.LONG  && markPrice <= pos.stopLossPrice) ||\n            (pos.direction == Direction.SHORT && markPrice >= pos.stopLossPrice)\n        );\n        require(tpHit || slHit, "Perp: TP/SL not triggered");\n\n        if (tpHit) emit TakeProfitTriggered(positionId, markPrice);\n        if (slHit) emit StopLossTriggered(positionId, markPrice);\n        _closePosition(positionId, markPrice, sp);\n    }\n\n    // ── Close ─────────────────────────────────────────────────────────────────\n\n    function closePositionWithPrice(uint256 positionId, MaisonPullOracle.SignedPrice calldata sp)\n        external nonReentrant positionExists(positionId) positionOpen(positionId)\n    {\n        require(positions[positionId].trader == msg.sender, "Perp: not your position");\n        _closePosition(positionId, oracle.verifyAndGetPrice(sp), sp);\n    }\n\n    function closeCopyPositionAtPrice(uint256 positionId, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata sp)\n        external onlySocialLayer positionExists(positionId) positionOpen(positionId)\n    {\n        _closePosition(positionId, exitPrice, sp);\n    }\n\n    function _closePosition(uint256 positionId, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata sp) internal {\n        Position storage pos = positions[positionId];\n        _applyFunding(positionId);\n\n        int256 rawPnl    = _calculatePnL(pos, exitPrice);\n        uint256 closeFee = (pos.size * CLOSE_FEE_BPS) / BASIS_POINTS;\n        int256 pnl       = rawPnl - int256(closeFee);\n\n        insuranceFund += (closeFee * INSURANCE_SHARE) / BASIS_POINTS;\n\n        if (pos.direction == Direction.LONG) markets[pos.asset].totalLongSize  -= pos.size;\n        else                                 markets[pos.asset].totalShortSize -= pos.size;\n\n        if (pnl < -int256(pos.margin)) {\n            uint256 shortfall = uint256(-pnl) - pos.margin;\n            insuranceFund = insuranceFund >= shortfall ? insuranceFund - shortfall : 0;\n            emit InsuranceFundUpdated(insuranceFund);\n        }\n\n        vault.releaseMargin(pos.trader, pos.margin, pnl, positionId);\n        pos.status      = Status.CLOSED;\n        pos.realisedPnl = pnl;\n        _removeFromOpenPositions(positionId);\n        emit PositionClosed(positionId, pos.trader, exitPrice, pnl, closeFee);\n\n        if (socialLayer != address(0)) {\n            try IMaisonSocial(socialLayer).onPositionClosed(positionId, pnl, exitPrice, sp) {} catch {}\n        }\n    }\n\n    // ── Liquidation ───────────────────────────────────────────────────────────\n\n    function liquidateWithPrice(uint256 positionId, MaisonPullOracle.SignedPrice calldata sp)\n        external nonReentrant positionExists(positionId) positionOpen(positionId)\n    {\n        uint256 markPrice = oracle.verifyAndGetPrice(sp);\n        Position storage pos = positions[positionId];\n        require(_isLiquidatable(pos, markPrice), "Perp: position healthy");\n\n        _applyFunding(positionId);\n        if (pos.direction == Direction.LONG) markets[pos.asset].totalLongSize  -= pos.size;\n        else                                 markets[pos.asset].totalShortSize -= pos.size;\n\n        int256 pnl = _calculatePnL(pos, markPrice);\n        if (pnl < -int256(pos.margin)) {\n            uint256 shortfall = uint256(-pnl) - pos.margin;\n            insuranceFund = insuranceFund >= shortfall ? insuranceFund - shortfall : 0;\n            emit InsuranceFundUpdated(insuranceFund);\n        }\n\n        vault.liquidate(pos.trader, pos.margin, positionId);\n        pos.status      = Status.LIQUIDATED;\n        pos.realisedPnl = pnl;\n        _removeFromOpenPositions(positionId);\n        emit PositionLiquidated(positionId, pos.trader, msg.sender, markPrice, pos.margin);\n\n        if (socialLayer != address(0)) {\n            try IMaisonSocial(socialLayer).onPositionClosed(positionId, pnl, markPrice, sp) {} catch {}\n        }\n    }\n\n    // ── Funding ───────────────────────────────────────────────────────────────\n\n    function settleFunding(bytes32 asset) external { _settleFunding(asset); }\n\n    function _settleFunding(bytes32 asset) internal {\n        Market storage m = markets[asset];\n        if (!m.active || block.timestamp < m.lastFundingTime + FUNDING_INTERVAL) return;\n        int256 rate = _computeFundingRate(asset);\n        m.cumulativeFundingRate += rate;\n        m.lastFundingTime = block.timestamp;\n        emit FundingSettled(asset, rate, block.timestamp);\n    }\n\n    function _computeFundingRate(bytes32 asset) internal view returns (int256) {\n        Market storage m = markets[asset];\n        uint256 total = m.totalLongSize + m.totalShortSize;\n        if (total == 0) return 0;\n        int256 rate = (int256(m.totalLongSize) - int256(m.totalShortSize)) * int256(FUNDING_RATE_MAX) / int256(total);\n        if (rate >  int256(FUNDING_RATE_MAX)) return  int256(FUNDING_RATE_MAX);\n        if (rate < -int256(FUNDING_RATE_MAX)) return -int256(FUNDING_RATE_MAX);\n        return rate;\n    }\n\n    function _applyFunding(uint256 positionId) internal {\n        Position storage pos = positions[positionId];\n        if (block.timestamp == pos.lastFundingTimestamp) return;\n        int256 rate = markets[pos.asset].cumulativeFundingRate;\n        if (rate == 0) return;\n        int256 payment = int256(pos.size) * rate / int256(BASIS_POINTS);\n        if (pos.direction == Direction.SHORT) payment = -payment;\n        pos.accruedFunding += payment;\n        pos.lastFundingTimestamp = block.timestamp;\n    }\n\n    // ── PnL / checks ─────────────────────────────────────────────────────────\n\n    function _calculatePnL(Position memory pos, uint256 exitPrice) internal pure returns (int256) {\n        int256 delta = pos.direction == Direction.LONG\n            ? int256(exitPrice) - int256(pos.entryPrice)\n            : int256(pos.entryPrice) - int256(exitPrice);\n        return delta * int256(pos.size) / int256(pos.entryPrice) + pos.accruedFunding;\n    }\n\n    function _isLiquidatable(Position memory pos, uint256 markPrice) internal pure returns (bool) {\n        return int256(pos.margin) + _calculatePnL(pos, markPrice) <= int256((pos.margin * MAINT_MARGIN_BPS) / BASIS_POINTS);\n    }\n\n    function getUnrealisedPnL(uint256 positionId) external view returns (int256) {\n        Position memory pos = positions[positionId];\n        if (pos.status != Status.OPEN) return 0;\n        (uint256 p,) = oracle.getLastPrice(pos.asset);\n        return p == 0 ? int256(0) : _calculatePnL(pos, p);\n    }\n\n    function isLiquidatable(uint256 positionId) external view returns (bool) {\n        Position memory pos = positions[positionId];\n        if (pos.status != Status.OPEN) return false;\n        (uint256 p,) = oracle.getLastPrice(pos.asset);\n        return p > 0 && _isLiquidatable(pos, p);\n    }\n\n    function getLiquidationPrice(uint256 positionId) external view returns (uint256) {\n        Position memory pos = positions[positionId];\n        uint256 buf = ((pos.margin - (pos.margin * MAINT_MARGIN_BPS) / BASIS_POINTS) * pos.entryPrice) / pos.size;\n        return pos.direction == Direction.LONG\n            ? (pos.entryPrice > buf ? pos.entryPrice - buf : 0)\n            : pos.entryPrice + buf;\n    }\n\n    // ── Market / helpers ──────────────────────────────────────────────────────\n\n    function _activateMarket(bytes32 asset) internal {\n        markets[asset] = Market(asset, 0, 0, block.timestamp, 0, true);\n        activeMarkets.push(asset);\n        emit MarketActivated(asset);\n    }\n\n    function activateMarket(bytes32 asset) external onlyOwner {\n        require(!markets[asset].active, "Perp: already active");\n        _activateMarket(asset);\n    }\n\n    function _removeFromOpenPositions(uint256 positionId) internal {\n        uint256 idx    = _openPositionIndex[positionId];\n        uint256 lastId = openPositionIds[openPositionIds.length - 1];\n        openPositionIds[idx] = lastId;\n        _openPositionIndex[lastId] = idx;\n        openPositionIds.pop();\n        delete _openPositionIndex[positionId];\n    }\n\n    function getPosition(uint256 id) external view returns (Position memory) { return positions[id]; }\n    function getTraderPositions(address t) external view returns (uint256[] memory) { return traderPositions[t]; }\n    function getOpenPositionCount() external view returns (uint256) { return openPositionIds.length; }\n    function getMarket(bytes32 asset) external view returns (Market memory) { return markets[asset]; }\n}', TRUE, FALSE, NULL, NULL, '"2026-04-09T20:49:45.557Z"', '"2026-04-09T20:49:45.557Z"', '0x8f457a8c4891952cec10859f7c1156697732f1dd', '0', '0', 'claimed', 'flamingobuidl@gmail.com') ON CONFLICT DO NOTHING;
INSERT INTO contracts (address, name, type, description, logo_url, website, twitter, github, audit_url, source_code, verified, flagged, flag_reason, verified_at, created_at, updated_at, deployer, tx_count, unique_users, badge, email) VALUES ('0xdd396e9d6f1fc2d29a18dab097737dbf295e4dc1', 'MaisonVault', 'DEX', 'USDC margin custody contract. Holds all trader collateral, tracks free vs locked margin per wallet, and handles profit/loss settlement and liquidation. Only callable by the position manager and social layer — traders interact through deposit and withdraw.', NULL, 'https://maison.up.railway.app', NULL, NULL, NULL, '// SPDX-License-Identifier: MIT\npragma solidity ^0.8.24;\n\n// src/interfaces/IArcUSDC.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// IArcUSDC\n//\n// Arc testnet USDC ERC-20 interface.\n// Address: 0x3600000000000000000000000000000000000000\n//\n// CRITICAL Arc-specific notes:\n//   - Native USDC gas balance uses 18 decimals (like ETH on Ethereum)\n//   - The ERC-20 interface (this file) uses 6 decimals\n//   - ALWAYS use the ERC-20 interface for token transfers and allowances\n//   - NEVER mix native balance (18 dec) with ERC-20 amounts (6 dec)\n//   - 1 USDC = 1_000_000 in ERC-20 units (6 decimals)\n// ─────────────────────────────────────────────────────────────────────────────\n\ninterface IArcUSDC {\n    // ── ERC-20 standard ──────────────────────────────────────────────────────\n    function totalSupply() external view returns (uint256);\n    function balanceOf(address account) external view returns (uint256);\n    function transfer(address to, uint256 amount) external returns (bool);\n    function allowance(address owner, address spender) external view returns (uint256);\n    function approve(address spender, uint256 amount) external returns (bool);\n    function transferFrom(address from, address to, uint256 amount) external returns (bool);\n\n    // ── Metadata ─────────────────────────────────────────────────────────────\n    function decimals() external view returns (uint8);   // returns 6\n    function symbol() external view returns (string memory);\n    function name() external view returns (string memory);\n\n    // ── Events ───────────────────────────────────────────────────────────────\n    event Transfer(address indexed from, address indexed to, uint256 value);\n    event Approval(address indexed owner, address indexed spender, uint256 value);\n}\n\n// src/MaisonPullOracle.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// MaisonPullOracle\n//\n// Pull-based oracle for MAISON on Arc testnet.\n// Prices are signed offchain by a trusted signer and submitted by the user\n// AT THE TIME of their transaction. Zero staleness possible.\n//\n// How it works:\n//   1. Offchain signer (Node.js) pulls price from Binance every 500ms\n//   2. Signer signs: keccak256(asset, price, timestamp)\n//   3. Signature is cached in the frontend\n//   4. When trader opens/closes, they include the signed price in their tx\n//   5. This contract verifies the signature onchain using ecrecover\n//   6. If valid and fresh (< MAX_AGE seconds), price is accepted\n//   7. If invalid or stale, entire transaction reverts\n//\n// Price precision: 6 decimals (matches USDC)\n//   BTC at $97,420 = 97_420_000_000\n// ─────────────────────────────────────────────────────────────────────────────\n\ncontract MaisonPullOracle {\n\n    // ── Constants ─────────────────────────────────────────────────────────────\n    uint256 public constant MAX_AGE        = 120;  // seconds — max price age\n    uint256 public constant PRICE_DECIMALS = 6;   // matches USDC\n\n    // ── State ─────────────────────────────────────────────────────────────────\n    address public owner;\n    address public trustedSigner; // only this address can sign valid prices\n\n    // Cache last accepted price per asset (for liquidation keeper reads)\n    struct CachedPrice {\n        uint256 price;\n        uint256 timestamp;\n    }\n    mapping(bytes32 => CachedPrice) public lastAccepted;\n\n    // ── Asset keys — must match signer and MaisonPerp ─────────────────────────\n    bytes32 public constant BTC  = keccak256("BTC");\n    bytes32 public constant ETH  = keccak256("ETH");\n    bytes32 public constant SOL  = keccak256("SOL");\n    bytes32 public constant EURC = keccak256("EURC");\n    bytes32 public constant BRLA = keccak256("BRLA");\n    bytes32 public constant MXNB = keccak256("MXNB");\n\n    // ── Events ────────────────────────────────────────────────────────────────\n    event PriceAccepted(bytes32 indexed asset, uint256 price, uint256 timestamp);\n    event SignerUpdated(address indexed oldSigner, address indexed newSigner);\n\n    // ── Structs ───────────────────────────────────────────────────────────────\n\n    // This is what gets passed in every trade transaction\n    struct SignedPrice {\n        bytes32 asset;      // keccak256("BTC") etc\n        uint256 price;      // 6 decimal precision\n        uint256 timestamp;  // unix timestamp when signer signed this\n        bytes   signature;  // 65-byte ECDSA signature\n    }\n\n    // ── Constructor ──────────────────────────────────────────────────────────\n    constructor(address _trustedSigner) {\n        require(_trustedSigner != address(0), "Oracle: zero signer");\n        owner         = msg.sender;\n        trustedSigner = _trustedSigner;\n    }\n\n    // ── Modifiers ─────────────────────────────────────────────────────────────\n    modifier onlyOwner() {\n        require(msg.sender == owner, "Oracle: not owner");\n        _;\n    }\n\n    // ── Core: verify and return price ─────────────────────────────────────────\n\n    /// @notice Verify a signed price and return it if valid\n    /// @dev Called internally by MaisonPerp on every open/close/liquidate\n    /// @param sp The signed price struct submitted by the user\n    /// @return price The verified price (6 decimals)\n    function verifyAndGetPrice(SignedPrice calldata sp)\n        external\n        returns (uint256 price)\n    {\n        // ── 1. Check price is fresh ───────────────────────────────────────────\n        require(sp.timestamp > 0, "Oracle: zero timestamp");\n        require(\n            block.timestamp <= sp.timestamp + MAX_AGE,\n            "Oracle: price too old"\n        );\n        require(\n            sp.timestamp <= block.timestamp + 5, // allow 5s clock drift\n            "Oracle: price from future"\n        );\n\n        // ── 2. Reconstruct the message the signer signed ──────────────────────\n        // Must exactly match what the offchain signer signs\n        bytes32 messageHash = _buildMessageHash(sp.asset, sp.price, sp.timestamp);\n\n        // ── 3. Recover signer from signature ──────────────────────────────────\n        address recovered = _recoverSigner(messageHash, sp.signature);\n        require(recovered == trustedSigner, "Oracle: invalid signature");\n\n        // ── 4. Sanity check price is non-zero ─────────────────────────────────\n        require(sp.price > 0, "Oracle: zero price");\n\n        // ── 5. Cache the accepted price ───────────────────────────────────────\n        // Liquidation keeper can read this without needing a signature\n        lastAccepted[sp.asset] = CachedPrice({\n            price:     sp.price,\n            timestamp: sp.timestamp\n        });\n\n        emit PriceAccepted(sp.asset, sp.price, sp.timestamp);\n\n        return sp.price;\n    }\n\n    /// @notice Read-only verify — does not update cache, for view calls\n    function verifyPrice(SignedPrice calldata sp) external view returns (uint256) {\n        require(block.timestamp <= sp.timestamp + MAX_AGE, "Oracle: price too old");\n        require(sp.timestamp <= block.timestamp + 5, "Oracle: price from future");\n\n        bytes32 messageHash = _buildMessageHash(sp.asset, sp.price, sp.timestamp);\n        address recovered   = _recoverSigner(messageHash, sp.signature);\n        require(recovered == trustedSigner, "Oracle: invalid signature");\n        require(sp.price > 0, "Oracle: zero price");\n\n        return sp.price;\n    }\n\n    /// @notice Get last cached price (for liquidation keeper / UI reads)\n    /// @dev This is NOT verified — use only for display and liquidation checks\n    ///      The keeper will always submit a fresh signed price when liquidating\n    function getLastPrice(bytes32 asset) external view returns (uint256 price, uint256 timestamp) {\n        CachedPrice memory cp = lastAccepted[asset];\n        return (cp.price, cp.timestamp);\n    }\n\n    /// @notice Check if cached price is still within acceptable age\n    function isCachedFresh(bytes32 asset) external view returns (bool) {\n        CachedPrice memory cp = lastAccepted[asset];\n        if (cp.timestamp == 0) return false;\n        return block.timestamp <= cp.timestamp + MAX_AGE;\n    }\n\n    // ── Signature helpers ─────────────────────────────────────────────────────\n\n    /// @notice Build the message hash that the offchain signer must sign\n    /// @dev MUST match exactly what the Node.js signer produces\n    ///      Format: "\x19Ethereum Signed Message:\n32" + keccak256(asset, price, timestamp)\n    function _buildMessageHash(\n        bytes32 asset,\n        uint256 price,\n        uint256 timestamp\n    ) internal pure returns (bytes32) {\n        // Inner hash: tightly packed encoding of the price data\n        bytes32 dataHash = keccak256(abi.encodePacked(\n            asset,\n            price,\n            timestamp\n        ));\n\n        // Ethereum signed message prefix (EIP-191 personal_sign format)\n        // This matches ethers.js signMessage() behaviour\n        return keccak256(abi.encodePacked(\n            "\x19Ethereum Signed Message:\n32",\n            dataHash\n        ));\n    }\n\n    /// @notice Recover signer address from message hash and signature\n    function _recoverSigner(\n        bytes32 messageHash,\n        bytes memory signature\n    ) internal pure returns (address) {\n        require(signature.length == 65, "Oracle: bad signature length");\n\n        bytes32 r;\n        bytes32 s;\n        uint8   v;\n\n        assembly {\n            r := mload(add(signature, 32))\n            s := mload(add(signature, 64))\n            v := byte(0, mload(add(signature, 96)))\n        }\n\n        // Normalise v (some signers return 0/1, EVM expects 27/28)\n        if (v < 27) v += 27;\n        require(v == 27 || v == 28, "Oracle: invalid v");\n\n        address recovered = ecrecover(messageHash, v, r, s);\n        require(recovered != address(0), "Oracle: ecrecover failed");\n\n        return recovered;\n    }\n\n    // ── Owner ─────────────────────────────────────────────────────────────────\n\n    /// @notice Rotate the trusted signer key\n    function setSigner(address newSigner) external onlyOwner {\n        require(newSigner != address(0), "Oracle: zero address");\n        emit SignerUpdated(trustedSigner, newSigner);\n        trustedSigner = newSigner;\n    }\n\n    function transferOwnership(address newOwner) external onlyOwner {\n        require(newOwner != address(0), "Oracle: zero address");\n        owner = newOwner;\n    }\n\n    // ── View: build message hash for offchain signing ─────────────────────────\n\n    /// @notice Helper for the offchain signer to verify it''s hashing correctly\n    function buildMessageHash(\n        bytes32 asset,\n        uint256 price,\n        uint256 timestamp\n    ) external pure returns (bytes32) {\n        return _buildMessageHash(asset, price, timestamp);\n    }\n}\n\n// src/MaisonVault.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// MaisonVault\n//\n// Holds all trader USDC margin on Arc testnet.\n// All amounts in USDC ERC-20 units (6 decimals).\n//\n// Arc-specific: uses USDC ERC-20 at 0x3600000000000000000000000000000000000000\n// NEVER interact with native Arc balance — always use the ERC-20 interface.\n//\n// Architecture:\n//   - Traders deposit USDC → credited as free margin\n//   - PositionManager locks margin when a position opens\n//   - PositionManager releases/adjusts margin when position closes\n//   - SocialLayer reads balances for copy fee payments\n// ─────────────────────────────────────────────────────────────────────────────\n\ncontract MaisonVault {\n\n    // ── Arc testnet USDC ERC-20 (6 decimals) ─────────────────────────────────\n    address  public constant USDC_ADDRESS = 0x3600000000000000000000000000000000000000;\n\n    // ── Access control ────────────────────────────────────────────────────────\n    address public owner;\n    address public positionManager;  // only contract that can lock/unlock margin\n    address public socialLayer;      // only contract that can pay copy fees\n\n    // ── Margin accounting ─────────────────────────────────────────────────────\n    // All values in USDC with 6 decimals\n\n    mapping(address => uint256) public freeMargin;   // available to open positions\n    mapping(address => uint256) public lockedMargin; // locked in open positions\n    mapping(address => uint256) public copyEarnings; // accumulated copy fees earned\n\n    // ── Protocol fee collection ───────────────────────────────────────────────\n    uint256 public protocolFees; // total accumulated, claimable by owner\n\n    // ── Events ────────────────────────────────────────────────────────────────\n    event Deposited(address indexed trader, uint256 amount);\n    event Withdrawn(address indexed trader, uint256 amount);\n    event MarginLocked(address indexed trader, uint256 amount, uint256 positionId);\n    event MarginReleased(address indexed trader, uint256 amount, uint256 positionId);\n    event MarginLiquidated(address indexed trader, uint256 amount, uint256 positionId);\n    event CopyFeeEarned(address indexed leader, uint256 amount);\n    event CopyFeePaid(address indexed copier, uint256 amount);\n    event CopyEarningsClaimed(address indexed leader, uint256 amount);\n    event ProtocolFeeCollected(uint256 amount);\n\n    // ── Constructor ──────────────────────────────────────────────────────────\n    constructor() {\n        owner = msg.sender;\n    }\n\n    // ── USDC getter — virtual so tests can inject a mock ─────────────────────\n    function getUSDC() internal view virtual returns (IArcUSDC) {\n        return IArcUSDC(USDC_ADDRESS);\n    }\n\n    // ── Access modifiers ──────────────────────────────────────────────────────\n    modifier onlyOwner() {\n        require(msg.sender == owner, "Vault: not owner");\n        _;\n    }\n\n    modifier onlyPositionManager() {\n        require(msg.sender == positionManager, "Vault: not position manager");\n        _;\n    }\n\n    modifier onlySocialLayer() {\n        require(msg.sender == socialLayer, "Vault: not social layer");\n        _;\n    }\n\n    modifier onlyAuthorized() {\n        require(\n            msg.sender == positionManager || msg.sender == socialLayer,\n            "Vault: not authorized"\n        );\n        _;\n    }\n\n    // ── Setup ─────────────────────────────────────────────────────────────────\n\n    function setPositionManager(address _pm) external onlyOwner {\n        require(_pm != address(0), "Vault: zero address");\n        positionManager = _pm;\n    }\n\n    function setSocialLayer(address _sl) external onlyOwner {\n        require(_sl != address(0), "Vault: zero address");\n        socialLayer = _sl;\n    }\n\n    function transferOwnership(address newOwner) external onlyOwner {\n        require(newOwner != address(0), "Vault: zero address");\n        owner = newOwner;\n    }\n\n    // ── Trader-facing ─────────────────────────────────────────────────────────\n\n    /// @notice Deposit USDC margin\n    /// @dev Trader must approve this contract first: USDC.approve(vault, amount)\n    /// @param amount Amount in USDC ERC-20 units (6 decimals). 100 USDC = 100_000_000\n    function deposit(uint256 amount) external {\n        require(amount > 0, "Vault: zero amount");\n\n        // Pull USDC from trader — uses ERC-20 transferFrom (6 decimals)\n        bool success = getUSDC().transferFrom(msg.sender, address(this), amount);\n        require(success, "Vault: USDC transfer failed");\n\n        freeMargin[msg.sender] += amount;\n\n        emit Deposited(msg.sender, amount);\n    }\n\n    /// @notice Withdraw free margin (not locked in positions)\n    function withdraw(uint256 amount) external {\n        require(amount > 0, "Vault: zero amount");\n        require(freeMargin[msg.sender] >= amount, "Vault: insufficient free margin");\n\n        freeMargin[msg.sender] -= amount;\n\n        bool success = getUSDC().transfer(msg.sender, amount);\n        require(success, "Vault: USDC transfer failed");\n\n        emit Withdrawn(msg.sender, amount);\n    }\n\n    /// @notice Claim accumulated copy earnings\n    function claimCopyEarnings() external {\n        uint256 earnings = copyEarnings[msg.sender];\n        require(earnings > 0, "Vault: no earnings");\n\n        copyEarnings[msg.sender] = 0;\n\n        bool success = getUSDC().transfer(msg.sender, earnings);\n        require(success, "Vault: USDC transfer failed");\n\n        emit CopyEarningsClaimed(msg.sender, earnings);\n    }\n\n    // ── PositionManager-facing ────────────────────────────────────────────────\n\n    /// @notice Lock margin when a position opens\n    function lockMargin(address trader, uint256 amount, uint256 positionId) external onlyPositionManager {\n        require(freeMargin[trader] >= amount, "Vault: insufficient margin");\n\n        freeMargin[trader]  -= amount;\n        lockedMargin[trader] += amount;\n\n        emit MarginLocked(trader, amount, positionId);\n    }\n\n    /// @notice Release locked margin back to free (position closed with PnL applied)\n    /// @param pnl Signed PnL — positive means trader profited, negative means loss\n    function releaseMargin(\n        address trader,\n        uint256 lockedAmount,\n        int256  pnl,\n        uint256 positionId\n    ) external onlyPositionManager {\n        require(lockedMargin[trader] >= lockedAmount, "Vault: margin accounting error");\n\n        lockedMargin[trader] -= lockedAmount;\n\n        if (pnl >= 0) {\n            // Profitable — return locked margin + profit\n            uint256 profit = uint256(pnl);\n            freeMargin[trader] += lockedAmount + profit;\n        } else {\n            // Loss — deduct from locked margin\n            uint256 loss = uint256(-pnl);\n            if (loss >= lockedAmount) {\n                // Full wipeout — trader loses entire margin for this position\n                // Remainder goes to insurance fund (protocol fees)\n                protocolFees += lockedAmount;\n            } else {\n                freeMargin[trader] += lockedAmount - loss;\n                protocolFees += loss; // loss goes to protocol/insurance\n            }\n        }\n\n        emit MarginReleased(trader, lockedAmount, positionId);\n    }\n\n    /// @notice Liquidate a position — locked margin goes to insurance fund\n    function liquidate(address trader, uint256 lockedAmount, uint256 positionId) external onlyPositionManager {\n        require(lockedMargin[trader] >= lockedAmount, "Vault: margin accounting error");\n\n        lockedMargin[trader] -= lockedAmount;\n        protocolFees += lockedAmount; // liquidated margin to insurance fund\n\n        emit MarginLiquidated(trader, lockedAmount, positionId);\n    }\n\n    // ── SocialLayer-facing ────────────────────────────────────────────────────\n\n    /// @notice Pay copy fee: deduct from copier''s free margin, credit to leader\n    /// @param copier  The trader who copied\n    /// @param leader  The trader who posted the position\n    /// @param totalFee Total fee amount (split between leader and protocol)\n    /// @param leaderShare Amount going to leader (rest goes to protocol)\n    function payCopyFee(\n        address copier,\n        address leader,\n        uint256 totalFee,\n        uint256 leaderShare\n    ) external onlySocialLayer {\n        require(freeMargin[copier] >= totalFee, "Vault: copier insufficient margin for fee");\n        require(leaderShare <= totalFee, "Vault: leader share exceeds total fee");\n\n        uint256 protocolShare = totalFee - leaderShare;\n\n        freeMargin[copier]    -= totalFee;\n        copyEarnings[leader]  += leaderShare;\n        protocolFees          += protocolShare;\n\n        emit CopyFeeEarned(leader, leaderShare);\n        emit CopyFeePaid(copier, totalFee);\n        emit ProtocolFeeCollected(protocolShare);\n    }\n\n    // ── Owner ─────────────────────────────────────────────────────────────────\n\n    /// @notice Withdraw accumulated protocol fees\n    function withdrawProtocolFees(address to) external onlyOwner {\n        require(protocolFees > 0, "Vault: no fees");\n        uint256 amount = protocolFees;\n        protocolFees = 0;\n        bool success = getUSDC().transfer(to, amount);\n        require(success, "Vault: transfer failed");\n    }\n\n    // ── Views ─────────────────────────────────────────────────────────────────\n\n    /// @notice Total margin (free + locked) for a trader\n    function totalMargin(address trader) external view returns (uint256) {\n        return freeMargin[trader] + lockedMargin[trader];\n    }\n\n    /// @notice Total USDC held in this vault (sanity check)\n    function totalUSDCHeld() external view returns (uint256) {\n        return getUSDC().balanceOf(address(this));\n    }\n}\n\n// src/MaisonPerp.sol\n\ninterface IMaisonSocial {\n    function onPositionClosed(uint256 positionId, int256 realisedPnl, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata signedPrice) external;\n}\n\ncontract MaisonPerp {\n\n    uint256 private _status = 1;\n    modifier nonReentrant() {\n        require(_status == 1, "Perp: reentrant call");\n        _status = 2;\n        _;\n        _status = 1;\n    }\n\n    uint256 public constant BASIS_POINTS    = 10_000;\n    uint256 public constant MAX_LEVERAGE    = 25;\n    uint256 public constant MIN_LEVERAGE    = 1;\n    uint256 public constant FUNDING_INTERVAL = 8 hours;\n    uint256 public constant FUNDING_RATE_MAX = 100;\n    uint256 public constant MAINT_MARGIN_BPS = 500;\n    uint256 public constant LIQ_FEE_BPS     = 100;\n    uint256 public constant OPEN_FEE_BPS    = 10;\n    uint256 public constant CLOSE_FEE_BPS   = 10;\n    uint256 public constant INSURANCE_SHARE = 2000;\n\n    MaisonVault      public immutable vault;\n    MaisonPullOracle public immutable oracle;\n    address          public owner;\n    address          public socialLayer;\n    uint256          public insuranceFund;\n    uint256          public nextPositionId = 1;\n\n    enum Direction { LONG, SHORT }\n    enum Status    { OPEN, CLOSED, LIQUIDATED }\n\n    struct Position {\n        uint256   id;\n        address   trader;\n        bytes32   asset;\n        Direction direction;\n        uint256   size;\n        uint256   margin;\n        uint256   leverage;\n        uint256   entryPrice;\n        uint256   openTimestamp;\n        uint256   lastFundingTimestamp;\n        int256    accruedFunding;\n        Status    status;\n        bool      isPublic;\n        int256    realisedPnl;\n        uint256   takeProfitPrice;\n        uint256   stopLossPrice;\n    }\n\n    mapping(uint256 => Position)   public positions;\n    mapping(address => uint256[])  public traderPositions;\n    uint256[]                      public openPositionIds;\n    mapping(uint256 => uint256)    private _openPositionIndex;\n\n    struct Market {\n        bytes32 asset;\n        uint256 totalLongSize;\n        uint256 totalShortSize;\n        uint256 lastFundingTime;\n        int256  cumulativeFundingRate;\n        bool    active;\n    }\n\n    mapping(bytes32 => Market) public markets;\n    bytes32[]                  public activeMarkets;\n\n    event PositionOpened(uint256 indexed positionId, address indexed trader, bytes32 indexed asset, Direction direction, uint256 size, uint256 margin, uint256 leverage, uint256 entryPrice, bool isPublic);\n    event PositionClosed(uint256 indexed positionId, address indexed trader, uint256 exitPrice, int256 pnl, uint256 fee);\n    event PositionLiquidated(uint256 indexed positionId, address indexed trader, address indexed liquidator, uint256 markPrice, uint256 marginLost);\n    event TakeProfitTriggered(uint256 indexed positionId, uint256 exitPrice);\n    event StopLossTriggered(uint256 indexed positionId, uint256 exitPrice);\n    event TPSLUpdated(uint256 indexed positionId, uint256 tpPrice, uint256 slPrice);\n    event FundingSettled(bytes32 indexed asset, int256 fundingRate, uint256 timestamp);\n    event InsuranceFundUpdated(uint256 newBalance);\n    event MarketActivated(bytes32 indexed asset);\n\n    constructor(address _vault, address _oracle) {\n        vault  = MaisonVault(_vault);\n        oracle = MaisonPullOracle(_oracle);\n        owner  = msg.sender;\n        _activateMarket(keccak256("BTC"));\n        _activateMarket(keccak256("ETH"));\n        _activateMarket(keccak256("SOL"));\n        _activateMarket(keccak256("EURC"));\n        _activateMarket(keccak256("BRLA"));\n        _activateMarket(keccak256("MXNB"));\n    }\n\n    modifier onlyOwner() { require(msg.sender == owner, "Perp: not owner"); _; }\n    modifier onlySocialLayer() { require(msg.sender == socialLayer, "Perp: not social layer"); _; }\n    modifier positionExists(uint256 id) { require(positions[id].id == id, "Perp: not found"); _; }\n    modifier positionOpen(uint256 id) { require(positions[id].status == Status.OPEN, "Perp: not open"); _; }\n\n    function setSocialLayer(address _sl) external onlyOwner { socialLayer = _sl; }\n    function transferOwnership(address n) external onlyOwner { owner = n; }\n\n    // ── Open ──────────────────────────────────────────────────────────────────\n\n    function openPositionWithPrice(\n        bytes32 asset, Direction direction, uint256 margin, uint256 leverage, bool isPublic,\n        MaisonPullOracle.SignedPrice calldata sp\n    ) external nonReentrant returns (uint256) {\n        return _openPosition(msg.sender, asset, direction, margin, leverage, isPublic, oracle.verifyAndGetPrice(sp));\n    }\n\n    function openCopyPosition(\n        address copier, bytes32 asset, Direction direction, uint256 margin, uint256 leverage,\n        MaisonPullOracle.SignedPrice calldata sp\n    ) external onlySocialLayer nonReentrant returns (uint256) {\n        return _openPosition(copier, asset, direction, margin, leverage, false, oracle.verifyAndGetPrice(sp));\n    }\n\n    function _openPosition(address trader, bytes32 asset, Direction direction, uint256 margin, uint256 leverage, bool isPublic, uint256 entryPrice) internal returns (uint256 positionId) {\n        require(markets[asset].active,                                "Perp: market not active");\n        require(leverage >= MIN_LEVERAGE && leverage <= MAX_LEVERAGE, "Perp: invalid leverage");\n        require(margin > 0,                                           "Perp: zero margin");\n        require(entryPrice > 0,                                       "Perp: zero price");\n        require(vault.freeMargin(trader) >= margin,                   "Perp: insufficient margin");\n\n        uint256 size    = margin * leverage;\n        uint256 openFee = (size * OPEN_FEE_BPS) / BASIS_POINTS;\n        require(vault.freeMargin(trader) >= margin + openFee, "Perp: insufficient margin for fee");\n\n        _settleFunding(asset);\n        if (direction == Direction.LONG) markets[asset].totalLongSize  += size;\n        else                             markets[asset].totalShortSize += size;\n\n        positionId = nextPositionId++;\n        vault.lockMargin(trader, margin + openFee, positionId);\n\n        uint256 ins = (openFee * INSURANCE_SHARE) / BASIS_POINTS;\n        insuranceFund += ins;\n\n        positions[positionId] = Position({\n            id: positionId, trader: trader, asset: asset, direction: direction,\n            size: size, margin: margin, leverage: leverage, entryPrice: entryPrice,\n            openTimestamp: block.timestamp, lastFundingTimestamp: block.timestamp,\n            accruedFunding: 0, status: Status.OPEN, isPublic: isPublic,\n            realisedPnl: 0, takeProfitPrice: 0, stopLossPrice: 0\n        });\n\n        traderPositions[trader].push(positionId);\n        openPositionIds.push(positionId);\n        _openPositionIndex[positionId] = openPositionIds.length - 1;\n        emit PositionOpened(positionId, trader, asset, direction, size, margin, leverage, entryPrice, isPublic);\n        return positionId;\n    }\n\n    // ── TP/SL ─────────────────────────────────────────────────────────────────\n\n    function setTPSL(uint256 positionId, uint256 tpPrice, uint256 slPrice)\n        external positionExists(positionId) positionOpen(positionId)\n    {\n        Position storage pos = positions[positionId];\n        require(pos.trader == msg.sender, "Perp: not your position");\n        if (tpPrice > 0) {\n            if (pos.direction == Direction.LONG)  require(tpPrice > pos.entryPrice, "Perp: TP above entry for long");\n            else                                  require(tpPrice < pos.entryPrice, "Perp: TP below entry for short");\n        }\n        if (slPrice > 0) {\n            if (pos.direction == Direction.LONG)  require(slPrice < pos.entryPrice, "Perp: SL below entry for long");\n            else                                  require(slPrice > pos.entryPrice, "Perp: SL above entry for short");\n        }\n        pos.takeProfitPrice = tpPrice;\n        pos.stopLossPrice   = slPrice;\n        emit TPSLUpdated(positionId, tpPrice, slPrice);\n    }\n\n    function triggerTPSL(uint256 positionId, MaisonPullOracle.SignedPrice calldata sp)\n        external nonReentrant positionExists(positionId) positionOpen(positionId)\n    {\n        uint256 markPrice = oracle.verifyAndGetPrice(sp);\n        Position storage pos = positions[positionId];\n\n        bool tpHit = pos.takeProfitPrice > 0 && (\n            (pos.direction == Direction.LONG  && markPrice >= pos.takeProfitPrice) ||\n            (pos.direction == Direction.SHORT && markPrice <= pos.takeProfitPrice)\n        );\n        bool slHit = pos.stopLossPrice > 0 && (\n            (pos.direction == Direction.LONG  && markPrice <= pos.stopLossPrice) ||\n            (pos.direction == Direction.SHORT && markPrice >= pos.stopLossPrice)\n        );\n        require(tpHit || slHit, "Perp: TP/SL not triggered");\n\n        if (tpHit) emit TakeProfitTriggered(positionId, markPrice);\n        if (slHit) emit StopLossTriggered(positionId, markPrice);\n        _closePosition(positionId, markPrice, sp);\n    }\n\n    // ── Close ─────────────────────────────────────────────────────────────────\n\n    function closePositionWithPrice(uint256 positionId, MaisonPullOracle.SignedPrice calldata sp)\n        external nonReentrant positionExists(positionId) positionOpen(positionId)\n    {\n        require(positions[positionId].trader == msg.sender, "Perp: not your position");\n        _closePosition(positionId, oracle.verifyAndGetPrice(sp), sp);\n    }\n\n    function closeCopyPositionAtPrice(uint256 positionId, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata sp)\n        external onlySocialLayer positionExists(positionId) positionOpen(positionId)\n    {\n        _closePosition(positionId, exitPrice, sp);\n    }\n\n    function _closePosition(uint256 positionId, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata sp) internal {\n        Position storage pos = positions[positionId];\n        _applyFunding(positionId);\n\n        int256 rawPnl    = _calculatePnL(pos, exitPrice);\n        uint256 closeFee = (pos.size * CLOSE_FEE_BPS) / BASIS_POINTS;\n        int256 pnl       = rawPnl - int256(closeFee);\n\n        insuranceFund += (closeFee * INSURANCE_SHARE) / BASIS_POINTS;\n\n        if (pos.direction == Direction.LONG) markets[pos.asset].totalLongSize  -= pos.size;\n        else                                 markets[pos.asset].totalShortSize -= pos.size;\n\n        if (pnl < -int256(pos.margin)) {\n            uint256 shortfall = uint256(-pnl) - pos.margin;\n            insuranceFund = insuranceFund >= shortfall ? insuranceFund - shortfall : 0;\n            emit InsuranceFundUpdated(insuranceFund);\n        }\n\n        vault.releaseMargin(pos.trader, pos.margin, pnl, positionId);\n        pos.status      = Status.CLOSED;\n        pos.realisedPnl = pnl;\n        _removeFromOpenPositions(positionId);\n        emit PositionClosed(positionId, pos.trader, exitPrice, pnl, closeFee);\n\n        if (socialLayer != address(0)) {\n            try IMaisonSocial(socialLayer).onPositionClosed(positionId, pnl, exitPrice, sp) {} catch {}\n        }\n    }\n\n    // ── Liquidation ───────────────────────────────────────────────────────────\n\n    function liquidateWithPrice(uint256 positionId, MaisonPullOracle.SignedPrice calldata sp)\n        external nonReentrant positionExists(positionId) positionOpen(positionId)\n    {\n        uint256 markPrice = oracle.verifyAndGetPrice(sp);\n        Position storage pos = positions[positionId];\n        require(_isLiquidatable(pos, markPrice), "Perp: position healthy");\n\n        _applyFunding(positionId);\n        if (pos.direction == Direction.LONG) markets[pos.asset].totalLongSize  -= pos.size;\n        else                                 markets[pos.asset].totalShortSize -= pos.size;\n\n        int256 pnl = _calculatePnL(pos, markPrice);\n        if (pnl < -int256(pos.margin)) {\n            uint256 shortfall = uint256(-pnl) - pos.margin;\n            insuranceFund = insuranceFund >= shortfall ? insuranceFund - shortfall : 0;\n            emit InsuranceFundUpdated(insuranceFund);\n        }\n\n        vault.liquidate(pos.trader, pos.margin, positionId);\n        pos.status      = Status.LIQUIDATED;\n        pos.realisedPnl = pnl;\n        _removeFromOpenPositions(positionId);\n        emit PositionLiquidated(positionId, pos.trader, msg.sender, markPrice, pos.margin);\n\n        if (socialLayer != address(0)) {\n            try IMaisonSocial(socialLayer).onPositionClosed(positionId, pnl, markPrice, sp) {} catch {}\n        }\n    }\n\n    // ── Funding ───────────────────────────────────────────────────────────────\n\n    function settleFunding(bytes32 asset) external { _settleFunding(asset); }\n\n    function _settleFunding(bytes32 asset) internal {\n        Market storage m = markets[asset];\n        if (!m.active || block.timestamp < m.lastFundingTime + FUNDING_INTERVAL) return;\n        int256 rate = _computeFundingRate(asset);\n        m.cumulativeFundingRate += rate;\n        m.lastFundingTime = block.timestamp;\n        emit FundingSettled(asset, rate, block.timestamp);\n    }\n\n    function _computeFundingRate(bytes32 asset) internal view returns (int256) {\n        Market storage m = markets[asset];\n        uint256 total = m.totalLongSize + m.totalShortSize;\n        if (total == 0) return 0;\n        int256 rate = (int256(m.totalLongSize) - int256(m.totalShortSize)) * int256(FUNDING_RATE_MAX) / int256(total);\n        if (rate >  int256(FUNDING_RATE_MAX)) return  int256(FUNDING_RATE_MAX);\n        if (rate < -int256(FUNDING_RATE_MAX)) return -int256(FUNDING_RATE_MAX);\n        return rate;\n    }\n\n    function _applyFunding(uint256 positionId) internal {\n        Position storage pos = positions[positionId];\n        if (block.timestamp == pos.lastFundingTimestamp) return;\n        int256 rate = markets[pos.asset].cumulativeFundingRate;\n        if (rate == 0) return;\n        int256 payment = int256(pos.size) * rate / int256(BASIS_POINTS);\n        if (pos.direction == Direction.SHORT) payment = -payment;\n        pos.accruedFunding += payment;\n        pos.lastFundingTimestamp = block.timestamp;\n    }\n\n    // ── PnL / checks ─────────────────────────────────────────────────────────\n\n    function _calculatePnL(Position memory pos, uint256 exitPrice) internal pure returns (int256) {\n        int256 delta = pos.direction == Direction.LONG\n            ? int256(exitPrice) - int256(pos.entryPrice)\n            : int256(pos.entryPrice) - int256(exitPrice);\n        return delta * int256(pos.size) / int256(pos.entryPrice) + pos.accruedFunding;\n    }\n\n    function _isLiquidatable(Position memory pos, uint256 markPrice) internal pure returns (bool) {\n        return int256(pos.margin) + _calculatePnL(pos, markPrice) <= int256((pos.margin * MAINT_MARGIN_BPS) / BASIS_POINTS);\n    }\n\n    function getUnrealisedPnL(uint256 positionId) external view returns (int256) {\n        Position memory pos = positions[positionId];\n        if (pos.status != Status.OPEN) return 0;\n        (uint256 p,) = oracle.getLastPrice(pos.asset);\n        return p == 0 ? int256(0) : _calculatePnL(pos, p);\n    }\n\n    function isLiquidatable(uint256 positionId) external view returns (bool) {\n        Position memory pos = positions[positionId];\n        if (pos.status != Status.OPEN) return false;\n        (uint256 p,) = oracle.getLastPrice(pos.asset);\n        return p > 0 && _isLiquidatable(pos, p);\n    }\n\n    function getLiquidationPrice(uint256 positionId) external view returns (uint256) {\n        Position memory pos = positions[positionId];\n        uint256 buf = ((pos.margin - (pos.margin * MAINT_MARGIN_BPS) / BASIS_POINTS) * pos.entryPrice) / pos.size;\n        return pos.direction == Direction.LONG\n            ? (pos.entryPrice > buf ? pos.entryPrice - buf : 0)\n            : pos.entryPrice + buf;\n    }\n\n    // ── Market / helpers ──────────────────────────────────────────────────────\n\n    function _activateMarket(bytes32 asset) internal {\n        markets[asset] = Market(asset, 0, 0, block.timestamp, 0, true);\n        activeMarkets.push(asset);\n        emit MarketActivated(asset);\n    }\n\n    function activateMarket(bytes32 asset) external onlyOwner {\n        require(!markets[asset].active, "Perp: already active");\n        _activateMarket(asset);\n    }\n\n    function _removeFromOpenPositions(uint256 positionId) internal {\n        uint256 idx    = _openPositionIndex[positionId];\n        uint256 lastId = openPositionIds[openPositionIds.length - 1];\n        openPositionIds[idx] = lastId;\n        _openPositionIndex[lastId] = idx;\n        openPositionIds.pop();\n        delete _openPositionIndex[positionId];\n    }\n\n    function getPosition(uint256 id) external view returns (Position memory) { return positions[id]; }\n    function getTraderPositions(address t) external view returns (uint256[] memory) { return traderPositions[t]; }\n    function getOpenPositionCount() external view returns (uint256) { return openPositionIds.length; }\n    function getMarket(bytes32 asset) external view returns (Market memory) { return markets[asset]; }\n}\n\n// src/MaisonSocial.sol\n\n// ─────────────────────────────────────────────────────────────────────────────\n// MaisonSocial\n//\n// The social layer of MAISON. This is what makes it different from every\n// other perp DEX. Handles:\n//\n//   1. Trader profiles — onchain reputation, win rate, stats\n//   2. Follow graph — who follows who\n//   3. Public position feed — visible positions from followed traders\n//   4. Copy trading — one-click entry mirroring a leader''s position\n//   5. Copy fee distribution — leader earns when copier profits\n//\n// All data is onchain on Arc. Reputation is permanent and portable.\n// ─────────────────────────────────────────────────────────────────────────────\n\ncontract MaisonSocial {\n\n    // ── Constants ─────────────────────────────────────────────────────────────\n    uint256 public constant BASIS_POINTS      = 10_000;\n    uint256 public constant COPY_FEE_BPS      = 800;    // 8% of copier profit goes to leader\n    uint256 public constant PROTOCOL_SHARE_BPS = 100;   // 1% of copier profit to protocol\n    uint256 public constant MAX_COPY_WINDOW   = 30 minutes; // max time to copy a position\n    uint256 public constant MIN_COPY_MARGIN   = 1_000_000;  // 1 USDC minimum copy size\n\n    // ── Dependencies ──────────────────────────────────────────────────────────\n    MaisonPerp   public immutable perp;\n    MaisonVault  public immutable vault;\n    address      public owner;\n\n    // ── Trader profiles ───────────────────────────────────────────────────────\n    struct TraderProfile {\n        address wallet;\n        string  handle;          // optional display name\n        uint256 totalTrades;\n        uint256 winningTrades;\n        uint256 totalVolume;     // USDC notional traded (6 decimals)\n        uint256 followerCount;\n        uint256 copyVolume;      // total USDC copied by others\n        uint256 totalCopyEarned; // lifetime copy fees earned\n        uint256 joinedAt;\n        bool    isRegistered;\n    }\n\n    mapping(address => TraderProfile) public profiles;\n    address[] public allTraders;\n\n    // ── Follow graph ──────────────────────────────────────────────────────────\n    // leader → set of followers\n    mapping(address => mapping(address => bool)) public isFollowing;\n    mapping(address => address[])                public followers;\n    mapping(address => address[])                public following;\n\n    // ── Copy tracking ─────────────────────────────────────────────────────────\n    struct CopyLink {\n        uint256 leaderPositionId;  // position being copied\n        uint256 copierPositionId;  // copier''s own position\n        address leader;\n        address copier;\n        uint256 copierMargin;      // USDC margin the copier put in\n        uint256 openTimestamp;\n        bool    settled;\n        bool    autoClose;\n    }\n\n    mapping(uint256 => CopyLink)  public copyLinks;  // copyLinkId → link\n    mapping(uint256 => uint256[]) public positionCopies;\n    mapping(uint256 => uint256)   public copierPositionToLink; // leaderPositionId → copyLinkIds\n    mapping(address => uint256[]) public traderCopyLinks; // trader → copyLinkIds as copier\n    uint256 public nextCopyLinkId = 1;\n\n    // ── Position copy window ──────────────────────────────────────────────────\n    // Track when a public position was opened so we can enforce copy window\n    mapping(uint256 => uint256) public positionPublicTimestamp;\n\n    // ── Events ────────────────────────────────────────────────────────────────\n    event ProfileRegistered(address indexed trader, string handle);\n    event ProfileUpdated(address indexed trader, string handle);\n    event Followed(address indexed follower, address indexed leader);\n    event Unfollowed(address indexed follower, address indexed leader);\n    event PositionCopied(\n        uint256 indexed copyLinkId,\n        uint256 indexed leaderPositionId,\n        uint256 indexed copierPositionId,\n        address leader,\n        address copier,\n        uint256 copierMargin\n    );\n    event CopyPositionAutoClosed(uint256 indexed copyLinkId, uint256 copierPositionId);\n    event CopyFeeSettled(\n        uint256 indexed copyLinkId,\n        address indexed leader,\n        address indexed copier,\n        uint256 leaderFee,\n        uint256 protocolFee,\n        int256  copierPnl\n    );\n    event TradeStatsUpdated(\n        address indexed trader,\n        uint256 totalTrades,\n        uint256 winningTrades,\n        uint256 totalVolume\n    );\n\n    // ── Constructor ──────────────────────────────────────────────────────────\n    constructor(address _perp, address _vault) {\n        perp  = MaisonPerp(_perp);\n        vault = MaisonVault(_vault);\n        owner = msg.sender;\n    }\n\n    // ── Modifier ──────────────────────────────────────────────────────────────\n    modifier onlyOwner() {\n        require(msg.sender == owner, "Social: not owner");\n        _;\n    }\n\n    // ── Profile management ────────────────────────────────────────────────────\n\n    /// @notice Register or update your trader profile\n    /// @param handle Optional display name (can be empty, max 32 chars)\n    function registerProfile(string calldata handle) external {\n        require(bytes(handle).length <= 32, "Social: handle too long");\n\n        if (!profiles[msg.sender].isRegistered) {\n            profiles[msg.sender] = TraderProfile({\n                wallet:           msg.sender,\n                handle:           handle,\n                totalTrades:      0,\n                winningTrades:    0,\n                totalVolume:      0,\n                followerCount:    0,\n                copyVolume:       0,\n                totalCopyEarned:  0,\n                joinedAt:         block.timestamp,\n                isRegistered:     true\n            });\n            allTraders.push(msg.sender);\n            emit ProfileRegistered(msg.sender, handle);\n        } else {\n            profiles[msg.sender].handle = handle;\n            emit ProfileUpdated(msg.sender, handle);\n        }\n    }\n\n    // ── Follow system ─────────────────────────────────────────────────────────\n\n    /// @notice Follow a trader — you''ll see their public positions in your feed\n    function follow(address leader) external {\n        require(leader != msg.sender, "Social: cannot follow yourself");\n        require(!isFollowing[leader][msg.sender], "Social: already following");\n        require(leader != address(0), "Social: zero address");\n\n        isFollowing[leader][msg.sender] = true;\n        followers[leader].push(msg.sender);\n        following[msg.sender].push(leader);\n\n        profiles[leader].followerCount++;\n\n        // Auto-register if not already\n        _autoRegister(msg.sender);\n        _autoRegister(leader);\n\n        emit Followed(msg.sender, leader);\n    }\n\n    /// @notice Unfollow a trader\n    function unfollow(address leader) external {\n        require(isFollowing[leader][msg.sender], "Social: not following");\n\n        isFollowing[leader][msg.sender] = false;\n\n        // Remove from followers array (swap and pop)\n        _removeFromArray(followers[leader], msg.sender);\n        _removeFromAddressArray(following[msg.sender], leader);\n\n        if (profiles[leader].followerCount > 0) {\n            profiles[leader].followerCount--;\n        }\n\n        emit Unfollowed(msg.sender, leader);\n    }\n\n    // ── Copy trading ──────────────────────────────────────────────────────────\n\n    /// @notice Copy a leader''s open public position with your own margin\n    /// @param leaderPositionId  The position ID to copy\n    /// @param copierMargin      USDC margin to put in (6 decimals)\n    /// @param signedPrice       Fresh signed price from the price signer\n    function copyPosition(\n        uint256 leaderPositionId,\n        uint256 copierMargin,\n        bool    autoClose,\n        MaisonPullOracle.SignedPrice calldata signedPrice\n    ) external returns (uint256 copyLinkId) {\n        // ── Validate position is copyable ─────────────────────────────────────\n        MaisonPerp.Position memory leaderPos = perp.getPosition(leaderPositionId);\n\n        require(leaderPos.status == MaisonPerp.Status.OPEN, "Social: position not open");\n        require(leaderPos.isPublic, "Social: position is private");\n        require(leaderPos.trader != msg.sender, "Social: cannot copy yourself");\n        require(copierMargin >= MIN_COPY_MARGIN, "Social: margin too small");\n        require(\n            vault.freeMargin(msg.sender) >= copierMargin,\n            "Social: insufficient margin"\n        );\n\n        // ── Check copy window ─────────────────────────────────────────────────\n        uint256 publicTime = positionPublicTimestamp[leaderPositionId];\n        if (publicTime == 0) publicTime = leaderPos.openTimestamp;\n        require(\n            block.timestamp <= publicTime + MAX_COPY_WINDOW,\n            "Social: copy window expired"\n        );\n\n        // ── Open copy position ────────────────────────────────────────────────\n        uint256 copierPositionId = perp.openCopyPosition(\n            msg.sender,\n            leaderPos.asset,\n            leaderPos.direction,\n            copierMargin,\n            leaderPos.leverage,\n            signedPrice\n        );\n\n        // ── Create copy link ──────────────────────────────────────────────────\n        copyLinkId = nextCopyLinkId++;\n\n        copyLinks[copyLinkId] = CopyLink({\n            leaderPositionId: leaderPositionId,\n            copierPositionId: copierPositionId,\n            leader:           leaderPos.trader,\n            copier:           msg.sender,\n            copierMargin:     copierMargin,\n            openTimestamp:    block.timestamp,\n            autoClose:        autoClose,\n            settled:          false\n        });\n\n        positionCopies[leaderPositionId].push(copyLinkId);\n        copierPositionToLink[copierPositionId] = copyLinkId;\n        traderCopyLinks[msg.sender].push(copyLinkId);\n\n        // ── Update stats ──────────────────────────────────────────────────────\n        profiles[leaderPos.trader].copyVolume += copierMargin * leaderPos.leverage;\n        _autoRegister(msg.sender);\n\n        emit PositionCopied(\n            copyLinkId,\n            leaderPositionId,\n            copierPositionId,\n            leaderPos.trader,\n            msg.sender,\n            copierMargin\n        );\n\n        return copyLinkId;\n    }\n\n    /// @notice Settle copy fee after a copier''s position closes\n    /// @dev Called when copier closes their position — calculates and pays fee to leader\n    function onPositionClosed(uint256 positionId, int256 realisedPnl, uint256 exitPrice, MaisonPullOracle.SignedPrice calldata signedPrice) external {\n        require(msg.sender == address(perp), "Social: not perp");\n        uint256[] memory links = positionCopies[positionId];\n        for (uint256 i = 0; i < links.length; i++) {\n            uint256 linkId = links[i];\n            CopyLink storage link = copyLinks[linkId];\n            if (link.settled) continue;\n            if (link.autoClose) {\n                MaisonPerp.Position memory copierPos = perp.getPosition(link.copierPositionId);\n                if (copierPos.status == MaisonPerp.Status.OPEN) {\n                    try perp.closeCopyPositionAtPrice(link.copierPositionId, exitPrice, signedPrice) {} catch {}\n                }\n            }\n            // Settle after close so realisedPnl is set\n            MaisonPerp.Position memory settled = perp.getPosition(link.copierPositionId);\n            if (settled.status != MaisonPerp.Status.OPEN) {\n                _settleFee(linkId);\n            }\n        }\n        // If this is a copier position closing, settle its fee\n        uint256 linkId = copierPositionToLink[positionId];\n        if (linkId != 0) {\n            _settleFee(linkId);\n        }\n\n        MaisonPerp.Position memory pos = perp.getPosition(positionId);\n        _updateTradeStats(pos.trader, pos.size, realisedPnl > 0);\n    }\n\n    /// @param copyLinkId The copy link to settle\n    function _settleFee(uint256 copyLinkId) internal {\n        CopyLink storage link = copyLinks[copyLinkId];\n        if (link.settled) return;\n        link.settled = true;\n        MaisonPerp.Position memory copierPos = perp.getPosition(link.copierPositionId);\n        int256 copierPnl = copierPos.realisedPnl;\n        uint256 leaderFee = 0;\n        uint256 protocolFee = 0;\n        if (copierPnl > 0) {\n            uint256 profit = uint256(copierPnl);\n            leaderFee   = (profit * COPY_FEE_BPS)      / BASIS_POINTS;\n            protocolFee = (profit * PROTOCOL_SHARE_BPS) / BASIS_POINTS;\n            uint256 totalFee = leaderFee + protocolFee;\n            if (vault.freeMargin(link.copier) >= totalFee) {\n                vault.payCopyFee(link.copier, link.leader, totalFee, leaderFee);\n                profiles[link.leader].totalCopyEarned += leaderFee;\n            }\n        }\n        _updateTradeStats(link.copier, link.copierMargin, copierPnl > 0);\n        emit CopyFeeSettled(copyLinkId, link.leader, link.copier, leaderFee, protocolFee, copierPnl);\n    }\n\n    function settleCopyFee(uint256 copyLinkId) external {\n        CopyLink storage link = copyLinks[copyLinkId];\n        require(!link.settled, "Social: already settled");\n        require(\n            msg.sender == link.copier || msg.sender == owner,\n            "Social: not authorised"\n        );\n\n        // ── Get copier''s position ─────────────────────────────────────────────\n        MaisonPerp.Position memory copierPos = perp.getPosition(link.copierPositionId);\n        require(\n            copierPos.status == MaisonPerp.Status.CLOSED ||\n            copierPos.status == MaisonPerp.Status.LIQUIDATED,\n            "Social: copier position still open"\n        );\n\n        link.settled = true;\n\n        // ── Get realised PnL from closed position ─────────────────────────────\n        // realisedPnl is stored on the position when it closes\n        int256 copierPnl = copierPos.realisedPnl;\n\n        uint256 leaderFee   = 0;\n        uint256 protocolFee = 0;\n\n        if (copierPnl > 0) {\n            uint256 profit = uint256(copierPnl);\n\n            // Leader gets COPY_FEE_BPS of copier profit\n            leaderFee   = (profit * COPY_FEE_BPS)      / BASIS_POINTS;\n            protocolFee = (profit * PROTOCOL_SHARE_BPS) / BASIS_POINTS;\n\n            uint256 totalFee = leaderFee + protocolFee;\n\n            // Pay from copier''s free margin\n            if (vault.freeMargin(link.copier) >= totalFee) {\n                vault.payCopyFee(link.copier, link.leader, totalFee, leaderFee);\n            }\n\n            // Update leader stats\n            profiles[link.leader].totalCopyEarned += leaderFee;\n        }\n\n        // ── Update trade stats ────────────────────────────────────────────────\n        _updateTradeStats(link.copier, link.copierMargin * copierPos.leverage, copierPnl > 0);\n\n        emit CopyFeeSettled(copyLinkId, link.leader, link.copier, leaderFee, protocolFee, copierPnl);\n    }\n\n    // ── Stats tracking ────────────────────────────────────────────────────────\n\n    /// @notice Called externally after a position closes to update stats\n    /// @dev In production, integrate with perp contract events\n    function recordTradeResult(address trader, uint256 volume, bool isWin) external {\n        // Only callable by perp contract or owner in this version\n        require(msg.sender == address(perp) || msg.sender == owner, "Social: not authorised");\n        _updateTradeStats(trader, volume, isWin);\n    }\n\n    function _updateTradeStats(address trader, uint256 volume, bool isWin) internal {\n        _autoRegister(trader);\n        TraderProfile storage profile = profiles[trader];\n\n        profile.totalTrades++;\n        profile.totalVolume += volume;\n        if (isWin) profile.winningTrades++;\n\n        emit TradeStatsUpdated(\n            trader,\n            profile.totalTrades,\n            profile.winningTrades,\n            profile.totalVolume\n        );\n    }\n\n    // ── Auto-register ─────────────────────────────────────────────────────────\n\n    function _autoRegister(address trader) internal {\n        if (!profiles[trader].isRegistered) {\n            profiles[trader] = TraderProfile({\n                wallet:           trader,\n                handle:           "",\n                totalTrades:      0,\n                winningTrades:    0,\n                totalVolume:      0,\n                followerCount:    0,\n                copyVolume:       0,\n                totalCopyEarned:  0,\n                joinedAt:         block.timestamp,\n                isRegistered:     true\n            });\n            allTraders.push(trader);\n        }\n    }\n\n    // ── Array helpers ─────────────────────────────────────────────────────────\n\n    function _removeFromArray(address[] storage arr, address target) internal {\n        for (uint256 i = 0; i < arr.length; i++) {\n            if (arr[i] == target) {\n                arr[i] = arr[arr.length - 1];\n                arr.pop();\n                return;\n            }\n        }\n    }\n\n    function _removeFromAddressArray(address[] storage arr, address target) internal {\n        _removeFromArray(arr, target);\n    }\n\n    // ── Views ─────────────────────────────────────────────────────────────────\n\n    /// @notice Get win rate as basis points (5500 = 55%)\n    function getWinRate(address trader) external view returns (uint256) {\n        TraderProfile memory p = profiles[trader];\n        if (p.totalTrades == 0) return 0;\n        return (p.winningTrades * BASIS_POINTS) / p.totalTrades;\n    }\n\n    /// @notice Get follower list for a trader\n    function getFollowers(address trader) external view returns (address[] memory) {\n        return followers[trader];\n    }\n\n    /// @notice Get following list for a trader\n    function getFollowing(address trader) external view returns (address[] memory) {\n        return following[trader];\n    }\n\n    /// @notice Get all copy links for a leader position\n    function getPositionCopies(uint256 positionId) external view returns (uint256[] memory) {\n        return positionCopies[positionId];\n    }\n\n    /// @notice Get copy count for a position\n    function getCopyCount(uint256 positionId) external view returns (uint256) {\n        return positionCopies[positionId].length;\n    }\n\n    /// @notice Get total trader count\n    function getTotalTraders() external view returns (uint256) {\n        return allTraders.length;\n    }\n\n    /// @notice Get top traders by follower count (returns up to `limit` addresses)\n    function getTopTradersByFollowers(uint256 limit) external view returns (address[] memory) {\n        uint256 count = allTraders.length < limit ? allTraders.length : limit;\n        address[] memory result = new address[](count);\n\n        // Simple selection sort for top N (fine for testnet)\n        address[] memory sorted = allTraders;\n        for (uint256 i = 0; i < count; i++) {\n            uint256 maxIdx = i;\n            for (uint256 j = i + 1; j < sorted.length; j++) {\n                if (profiles[sorted[j]].followerCount > profiles[sorted[maxIdx]].followerCount) {\n                    maxIdx = j;\n                }\n            }\n            (sorted[i], sorted[maxIdx]) = (sorted[maxIdx], sorted[i]);\n            result[i] = sorted[i];\n        }\n        return result;\n    }\n}', TRUE, FALSE, NULL, NULL, '"2026-04-09T21:33:29.542Z"', '"2026-04-09T21:33:29.542Z"', '0x8f457a8c4891952cec10859f7c1156697732f1dd', '0', '0', 'claimed', 'flamingobuidl@gmail.com') ON CONFLICT DO NOTHING;
INSERT INTO contracts (address, name, type, description, logo_url, website, twitter, github, audit_url, source_code, verified, flagged, flag_reason, verified_at, created_at, updated_at, deployer, tx_count, unique_users, badge, email) VALUES ('0x123babb979640dbc3bebf91539e8cdec6f0f6e55', 'Simiri Voucher', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, TRUE, FALSE, NULL, NULL, '"2026-04-09T21:39:55.957Z"', '"2026-04-09T21:39:55.957Z"', '0x82abaa2e9db65b2f012eb01c6d08696b8b59b798', '0', '0', 'claimed', 'simirionarc@gmail.com') ON CONFLICT DO NOTHING;
INSERT INTO contracts (address, name, type, description, logo_url, website, twitter, github, audit_url, source_code, verified, flagged, flag_reason, verified_at, created_at, updated_at, deployer, tx_count, unique_users, badge, email) VALUES ('0x443a47ef1025e047879b1ba08c94e6dedb354d54', 'ArcanaMarkets', 'defi', 'Onchain prediction market where users trade YES or NO on real world events using USDC on Arc Network.', NULL, 'https://arcanamarkets.netlify.app/', '@stephdreals', NULL, NULL, '// SPDX-License-Identifier: MIT\npragma solidity ^0.8.20;\n\ninterface IERC20 {\n    function transferFrom(address from, address to, uint256 amount) external returns (bool);\n    function transfer(address to, uint256 amount) external returns (bool);\n    function balanceOf(address account) external view returns (uint256);\n}\n\ncontract ArcanaMarkets {\n    IERC20 public usdc;\n    address public owner;\n    uint256 public marketCount;\n\n    struct Market {\n        uint256 id;\n        string title;\n        string category;\n        uint256 yesPool;\n        uint256 noPool;\n        uint256 endTime;\n        bool resolved;\n        bool cancelled;\n    }\n\n    mapping(uint256 => Market) public markets;\n    mapping(uint256 => mapping(address => uint256)) public yesShares;\n    mapping(uint256 => mapping(address => uint256)) public noShares;\n\n    event MarketCreated(uint256 indexed marketId, string title, uint256 endTime);\n    event SharesPurchased(uint256 indexed marketId, address indexed buyer, bool isYes, uint256 amount);\n    event MarketResolved(uint256 indexed marketId, bool yesWon);\n    event WinningsClaimed(uint256 indexed marketId, address indexed claimer, uint256 amount);\n\n    modifier onlyOwner() {\n        require(msg.sender == owner, "Not owner");\n        _;\n    }\n\n    constructor(address _usdc) {\n        usdc = IERC20(_usdc);\n        owner = msg.sender;\n    }\n\n    function createMarket(\n        string memory _title,\n        string memory _category,\n        uint256 _endTime\n    ) external onlyOwner returns (uint256) {\n        require(_endTime > block.timestamp, "End time must be in future");\n        marketCount++;\n        markets[marketCount] = Market({\n            id: marketCount,\n            title: _title,\n            category: _category,\n            yesPool: 0,\n            noPool: 0,\n            endTime: _endTime,\n            resolved: false,\n            cancelled: false\n        });\n        emit MarketCreated(marketCount, _title, _endTime);\n        return marketCount;\n    }\n\n    function buyShares(\n        uint256 _marketId,\n        bool _isYes,\n        uint256 _usdcAmount\n    ) external {\n        Market storage market = markets[_marketId];\n        require(!market.resolved, "Market already resolved");\n        require(!market.cancelled, "Market cancelled");\n        require(block.timestamp < market.endTime, "Market has ended");\n        require(_usdcAmount > 0, "Amount must be greater than 0");\n        require(usdc.transferFrom(msg.sender, address(this), _usdcAmount), "USDC transfer failed");\n        if (_isYes) {\n            market.yesPool += _usdcAmount;\n            yesShares[_marketId][msg.sender] += _usdcAmount;\n        } else {\n            market.noPool += _usdcAmount;\n            noShares[_marketId][msg.sender] += _usdcAmount;\n        }\n        emit SharesPurchased(_marketId, msg.sender, _isYes, _usdcAmount);\n    }\n\n    function resolveMarket(uint256 _marketId, bool _yesWon) external onlyOwner {\n        Market storage market = markets[_marketId];\n        require(!market.resolved, "Already resolved");\n        require(block.timestamp >= market.endTime, "Market not ended yet");\n        market.resolved = true;\n        emit MarketResolved(_marketId, _yesWon);\n    }\n\n    function claimWinnings(uint256 _marketId) external {\n        Market storage market = markets[_marketId];\n        require(market.resolved, "Market not resolved");\n        uint256 totalPool = market.yesPool + market.noPool;\n        uint256 winnings = 0;\n        if (market.yesPool > 0 && noShares[_marketId][msg.sender] == 0) {\n            uint256 shares = yesShares[_marketId][msg.sender];\n            if (shares > 0) {\n                winnings = (shares * totalPool) / market.yesPool;\n                yesShares[_marketId][msg.sender] = 0;\n            }\n        } else {\n            uint256 shares = noShares[_marketId][msg.sender];\n            if (shares > 0) {\n                winnings = (shares * totalPool) / market.noPool;\n                noShares[_marketId][msg.sender] = 0;\n            }\n        }\n        require(winnings > 0, "No winnings");\n        usdc.transfer(msg.\nsender, winnings);\n        emit WinningsClaimed(_marketId, msg.sender, winnings);\n    }\n\n    function cancelMarket(uint256 _marketId) external onlyOwner {\n        markets[_marketId].cancelled = true;\n    }\n\n    function refund(uint256 _marketId) external {\n        Market storage market = markets[_marketId];\n        require(market.cancelled, "Market not cancelled");\n        uint256 yes = yesShares[_marketId][msg.sender];\n        uint256 no = noShares[_marketId][msg.sender];\n        uint256 total = yes + no;\n        require(total > 0, "Nothing to refund");\n        yesShares[_marketId][msg.sender] = 0;\n        noShares[_marketId][msg.sender] = 0;\n        usdc.transfer(msg.sender, total);\n    }\n}', TRUE, FALSE, NULL, NULL, '"2026-04-10T08:35:22.333Z"', '"2026-04-10T08:35:22.333Z"', '0x3b4a7deb1274a6f802f45455c6a3998a1d8384d9', '0', '0', 'claimed', 'stephdreals@gmail.com') ON CONFLICT DO NOTHING;
INSERT INTO contracts (address, name, type, description, logo_url, website, twitter, github, audit_url, source_code, verified, flagged, flag_reason, verified_at, created_at, updated_at, deployer, tx_count, unique_users, badge, email) VALUES ('0x76398cfa526d4a76eaec0c4709d6b7c966e5abdb', 'AchRwaPrice Oracle', 'RWA', 'on chain price Oracle for achRWA', NULL, 'https://achswap.app/', 'AchProtocol', NULL, NULL, NULL, TRUE, FALSE, NULL, NULL, '"2026-04-11T15:30:59.279Z"', '"2026-04-11T15:30:59.279Z"', NULL, '0', '0', 'claimed', 'adib9710@gmail.com') ON CONFLICT DO NOTHING;
