INSERT INTO contracts (address, name, type, description, logo_url, website, twitter, github, audit_url, source_code, verified, flagged, flag_reason, verified_at, created_at, updated_at, deployer, tx_count, unique_users, badge, email) VALUES ('0x6fa971157cf2cd64bd9765e0ee14a4c89ba5defd', 'HelloArchitect', 'Basic custom smart contract', 'A foundational smart contract deployed on Arc Testnet using Foundry. Built as the onchain layer for the Arc AI Wallet Assistant — an AI-powered wallet interface that lets users interact with their Arc wallet in plain english using Circle''s Web3 APIs.', NULL, 'https://arc-wallet-assistant.vercel.app/', '@_Haboye', NULL, NULL, '// SPDX-License-Identifier: MIT\npragma solidity ^0.8.30;\n\ncontract HelloArchitect {\n    string private greeting;\n\n    event GreetingChanged(string newGreeting);\n\n    constructor() {\n        greeting = "Hello Architect!";\n    }\n\n    function setGreeting(string memory newGreeting) public {\n        greeting = newGreeting;\n        emit GreetingChanged(newGreeting);\n    }\n\n    function getGreeting() public view returns (string memory) {\n        return greeting;\n    }\n}', TRUE, FALSE, NULL, NULL, '"2026-04-11T15:45:41.683Z"', '"2026-04-11T15:45:41.683Z"', NULL, '0', '0', 'claimed', 'semilore05007@gmail.com') ON CONFLICT DO NOTHING;
