INSERT INTO events (id, name, tagline, type, description, date, end_date, timezone, location, is_online, link, logo_url, organizer, organizer_twitter, email, tags, badge, featured, approved, created_at) VALUES (5, 'VibeCard', 'Building the Agentic Economy on Arc: VibeCard', 'Webinar', 'Join Sam Sealey and Pete Budlong for this livestream as they discuss and demo VibeCard, a winning project from the recent LabLab Agentic Economy on Arc AI Hackathon.\n\nVibeCard is a viral growth network that rewards sharing with instant USDC paid into Circle Wallets on Arc: creators earn a split of the rewards and early sharers earn downstream rewards. The demo highlights Circle Wallets + x402 for multi‑recipient micropayments, reward splits, and a low‑friction onboarding experience.', '"2026-04-15T17:00:00.000Z"', '"2026-04-15T18:00:00.000Z"', 'UTC', NULL, TRUE, 'https://community.arc.network/events/building-the-agentic-economy-on-arc-vibecard', 'https://i.ibb.co/prxk0s4Y/1000017938-jpg.jpg', 'Arc House', '@arc', 'admin@arclens.app', '[]', 'official', FALSE, TRUE, '"2026-04-15T13:19:49.192Z"') ON CONFLICT DO NOTHING;
INSERT INTO events (id, name, tagline, type, description, date, end_date, timezone, location, is_online, link, logo_url, organizer, organizer_twitter, email, tags, badge, featured, approved, created_at) VALUES (4, 'Arc Discord Office Hours', 'Join us for a Discord exclusive Office Hours session.', 'Community Call', 'Join us for a Discord exclusive Office Hours session. This is a casual hangout with the Arc community team, and builders across the ecosystem. Ask questions and talk about the latest developments on Arc for the week!', '"2026-04-14T17:00:00.000Z"', '"2026-04-14T17:45:00.000Z"', 'UTC', NULL, TRUE, 'https://discord.com/events/1423729540160815207/1475911760987947079', 'https://i.ibb.co/vvwVX1qN/1000017899-jpg.jpg', 'ARC', '@Arc', 'admin@arclens.app', '[]', 'official', FALSE, TRUE, '"2026-04-13T11:56:10.239Z"') ON CONFLICT DO NOTHING;
INSERT INTO pending_updates (id, project_id, field, old_value, new_value, submitted_at, status) VALUES (1, 13, 'description', 'MAISON is a social perpetual DEX on Arc. Trade BTC, ETH, SOL and more with up to 25x leverage, copy other traders'' positions onchain with one click, and earn 8% of copiers'' profits automatically. Built with a pull oracle, CCTP bridge, and live leaderboard — all settled in native USDC.', 'MAISON is a social perpetual DEX on Arc. Trade BTC, ETH, SOL and more with up to 25x leverage, copy other traders positions onchain with one click, and earn 8% of copiers'' profits automatically. Built with a pull oracle, CCTP bridge, and live leaderboard — all settled in native USDC.', '"2026-04-09T15:59:58.994Z"', 'approved') ON CONFLICT DO NOTHING;
