INSERT INTO pending_updates (id, project_id, field, old_value, new_value, submitted_at, status) VALUES (13, 21, 'description', 'Tower Exchange is an AI-powered DEX aggregator built on the Arc blockchain. It is designed to unify liquidity across multiple decentralized exchanges while introducing an intelligent interaction layer that helps users understand and optimize their trading decisions. The platform combines efficient trade execution with AI-driven insights, making DeFi trading both simpler and more accessible.', 'Tower Exchange is the native stablecoin DEX aggregator powered by the Arc blockchain.\n\nWe aggregate liquidity from multiple DEXs to ensure users always get the best rates and deepest liquidity when swapping or moving stablecoins.\n\nBehind the scenes, AI optimizes routing and cross-chain execution, making every transaction fast, efficient, and seamless.\n\nOur focus is simple: remove complexity and deliver a smooth, one-interface experience for stablecoin transfers across chains.', '"2026-04-15T09:45:50.222Z"', 'approved') ON CONFLICT DO NOTHING;
